struct StreamChunkPairState {
    std::vector<unsigned char> last_chunk;
    // Some runtimes write variable-sized regions per Unlock(). To match against the precomputed
    // stream-chunk-pair map (fixed-size slices), we re-chunk the incoming bytes into fixed frames.
    std::vector<unsigned char> pending;
    size_t pending_off = 0;
    DWORD last_tick = 0;
    int active_handle = -1;   // last handle triggered for this buffer via stream-chunk matching
    DWORD active_tick = 0;
    bool phase_locked = false;
    size_t phase_offset = 0;
    int phase_scan_miss = 0;
    std::deque<uint64_t> fp_tokens;
    std::unordered_map<int, int> fp_votes;
    DWORD fp_vote_tick = 0;
    // Debugging (probe_mode): capture evidence of what PCM is actually being streamed for this buffer.
    bool dbg_init_logged = false;
    int dbg_pairs_logged = 0;
    int dbg_resync_logged = 0;
};
static std::mutex g_stream_chunk_mu;
static std::unordered_map<void *, StreamChunkPairState> g_stream_chunk_pair_state;
// For some Clickteam/MMFS2 streaming paths, Unlock() writes tiny slices (e.g. 0.05s) into a ring buffer.
// Hashing just that slice is too small/ambiguous to resolve a handle. To keep 1:1 deterministic matching
// without falling back to MMFS2 "hints" (which causes phantom subtitles), we can assemble the initial stream
// bytes after Play() and hash a full buffer window once enough bytes arrive.
struct StreamCapture {
    std::vector<unsigned char> data;
    DWORD start_tick;
    DWORD last_tick;
    DWORD target_bytes;
    WAVEFORMATEX wfx;
    bool active;
    int expected_handle;
    unsigned short expected_ord;
    unsigned long long expected_token;
    unsigned long long expected_uid;
    bool expected_triggered; // one-shot: used to start schedule for streamed dialogue when hash can't resolve
    DWORD last_trigger_tick;
    unsigned int last_trigger_bind_gen;
    bool last_bind_recent;
    bool no_hash;            // for ring-buffer streamed dialogue where full-buffer hash is unstable (e.g., Baby01)
};
static std::unordered_map<void *, StreamCapture> g_stream_caps;
