static inline unsigned long long MixEpisodeKeyU64(unsigned long long h, unsigned long long v) {
    // Simple 64-bit avalanche mix (MurmurHash3 finalizer style).
    h ^= v + 0x9E3779B97F4A7C15ULL + (h << 6) + (h >> 2);
    h ^= (h >> 33);
    h *= 0xff51afd7ed558ccdULL;
    h ^= (h >> 33);
    h *= 0xc4ceb9fe1a85ec53ULL;
    h ^= (h >> 33);
    return h;
}

static inline unsigned long long BuildMmfs2EpisodeKey(unsigned short ord,
                                                      unsigned long long token,
                                                      int raw_id,
                                                      int canonical_id,
                                                      DWORD ctx2,
                                                      int slot,
                                                      DWORD flags,
                                                      bool by_name) {
    unsigned long long h = 0x84222325CBF29CE4ULL;
    h = MixEpisodeKeyU64(h, token);
    h = MixEpisodeKeyU64(h, static_cast<unsigned long long>(ord));
    h = MixEpisodeKeyU64(h, static_cast<unsigned long long>(static_cast<unsigned int>(raw_id)));
    h = MixEpisodeKeyU64(h, static_cast<unsigned long long>(static_cast<unsigned int>(canonical_id)));
    h = MixEpisodeKeyU64(h, static_cast<unsigned long long>(ctx2));
    h = MixEpisodeKeyU64(h, static_cast<unsigned long long>(static_cast<unsigned int>(slot)));
    h = MixEpisodeKeyU64(h, static_cast<unsigned long long>(flags));
    h = MixEpisodeKeyU64(h, by_name ? 1ULL : 0ULL);
    // Keep non-zero so "0 means absent key" can remain a valid sentinel.
    return (h == 0ULL) ? 1ULL : h;
}

static inline void SetGlobalDialogHint(int handle, DWORD tick, unsigned short ord) {
    if (handle <= 0) {
        return;
    }
    unsigned long long v = (static_cast<unsigned long long>(tick) << 32) | static_cast<unsigned long long>(static_cast<unsigned int>(handle));
    g_last_dialog_hint_ord.store(ord, std::memory_order_relaxed);
    g_last_dialog_hint64.store(v, std::memory_order_relaxed);
}

static bool PeekRawGlobalDialogHint(int *out_handle, unsigned short *out_ord, DWORD *out_tick) {
    if (!out_handle) {
        return false;
    }
    unsigned long long v = g_last_dialog_hint64.load(std::memory_order_relaxed);
    if (v == 0) {
        return false;
    }
    DWORD tick = static_cast<DWORD>(v >> 32);
    int handle = static_cast<int>(static_cast<unsigned int>(v & 0xFFFFFFFFULL));
    if (handle <= 0) {
        return false;
    }
    *out_handle = handle;
    if (out_ord) {
        *out_ord = g_last_dialog_hint_ord.load(std::memory_order_relaxed);
    }
    if (out_tick) {
        *out_tick = tick;
    }
    return true;
}

static bool PeekGlobalDialogHint(DWORD now, int *out_handle, unsigned short *out_ord, DWORD *out_tick) {
    if (!out_handle) {
        return false;
    }
    unsigned long long v = g_last_dialog_hint64.load(std::memory_order_relaxed);
    if (v == 0) {
        return false;
    }
    DWORD tick = static_cast<DWORD>(v >> 32);
    int handle = static_cast<int>(static_cast<unsigned int>(v & 0xFFFFFFFFULL));
    if (handle <= 0) {
        return false;
    }
    if ((now - tick) > kTlsMatchWindowMs) {
        return false;
    }
    *out_handle = handle;
    if (out_ord) {
        *out_ord = g_last_dialog_hint_ord.load(std::memory_order_relaxed);
    }
    if (out_tick) {
        *out_tick = tick;
    }
    return true;
}

static bool ConsumeGlobalDialogHint(DWORD now, int *out_handle, unsigned short *out_ord) {
    if (!out_handle) {
        return false;
    }
    for (int i = 0; i < 3; i++) {
        unsigned long long v = g_last_dialog_hint64.load(std::memory_order_relaxed);
        if (v == 0) {
            return false;
        }
        DWORD tick = static_cast<DWORD>(v >> 32);
        int handle = static_cast<int>(static_cast<unsigned int>(v & 0xFFFFFFFFULL));
        if (handle <= 0) {
            return false;
        }
        if ((now - tick) > kTlsMatchWindowMs) {
            return false;
        }
        unsigned long long expected = v;
        if (g_last_dialog_hint64.compare_exchange_strong(expected, 0ULL, std::memory_order_relaxed)) {
            *out_handle = handle;
            if (out_ord) {
                *out_ord = g_last_dialog_hint_ord.load(std::memory_order_relaxed);
            }
            return true;
        }
        // someone updated the hint; retry and use the newest value instead of consuming a stale one
    }
    return false;
}

static bool HasRecentGlobalDialogHint(DWORD now) {
    unsigned long long v = g_last_dialog_hint64.load(std::memory_order_relaxed);
    if (v == 0) {
        return false;
    }
    DWORD tick = static_cast<DWORD>(v >> 32);
    int handle = static_cast<int>(static_cast<unsigned int>(v & 0xFFFFFFFFULL));
    if (handle <= 0) {
        return false;
    }
    return (now - tick) <= kTlsMatchWindowMs;
}

static bool HasRecentGlobalDialogHintForHandle(DWORD now, int handle, DWORD window_ms) {
    int gh = 0;
    unsigned short ghord = 0;
    DWORD ghtick = 0;
    if (!PeekGlobalDialogHint(now, &gh, &ghord, &ghtick)) {
        return false;
    }
    if (gh != handle || gh <= 0) {
        return false;
    }
    return (now - ghtick) <= window_ms;
}

static inline bool IsLegacyCoreStreamExpectedHandle(int handle) {
    if (handle <= 0) {
        return false;
    }
    // Conservative core stream class used by control-domain (+1/+61) normalization.
    // Keep this narrow to avoid promoting SFX/control ids into dialogue handles.
    if (handle == 97 || handle == 118 || handle == 130 || handle == 187 || handle == 191 || handle == 236 || handle == 237) {
        return true;
    }
    if (handle >= 192 && handle <= 200) {
        return true;
    }
    if (handle == 203 || handle == 204 || handle == 205) {
        return true;
    }
    return false;
}

static inline bool IsStreamExpectedHintHandle(int handle) {
    if (handle <= 0) {
        return false;
    }
    if (!g_stream_expected_dynamic_handles.empty() &&
        g_stream_expected_dynamic_handles.find(handle) != g_stream_expected_dynamic_handles.end()) {
        return true;
    }
    // "Baby*" dialogue clips are often streamed into a looping ring buffer and frequently cannot be
    // resolved by a stable full-buffer hash at Play() time. Treat these handles as "stream expected"
    // so we can prefer deterministic Unlock-based binding/triggers (SoundTracker / stream capture).
    //
    // Evidence: `sound_bank.tsv` (extracted from SisterLocation-compressed.mfa) contains multiple
    // Baby-named handles beyond 97 (Baby01). Matching on "baby" yields:
    // 97,118,130,187,191,192-200,203-205,237.
    return IsLegacyCoreStreamExpectedHandle(handle);
}

static inline bool IsAutoStreamHintSeedHandle(int handle) {
    if (handle <= 0) {
        return false;
    }
    // Preserve existing explicit stream class (Baby-family).
    if (IsStreamExpectedHintHandle(handle)) {
        return true;
    }
    // Expand stream-hint seeding to dialogue handles so non-Baby streamed dialogue
    // can bootstrap capture without per-handle hardcoding.
    if (!IsDialogHandleValue(handle)) {
        return false;
    }
    // Keep startup noise guard from control-shift remap path.
    if (handle >= 62 && handle <= 64) {
        return false;
    }
    return true;
}

static inline int GetStreamStrictMinNForHandle(int handle) {
    // Static closure (2026-03-01, global-domain compare):
    // - Most stream handles are globally unique at n=1.
    // - 130 requires n>=18 for full global uniqueness.
    // - 191 requires n>=24 for full global uniqueness.
    if (handle == 130) {
        return 18;
    }
    if (handle == 191) {
        return 24;
    }
    if (IsStreamExpectedHintHandle(handle)) {
        return 1;
    }
    return 1;
}


static inline bool IsControlShiftStartupSuppressedHandle(int handle) {
    // control_shift remap raw_id(1..3) -> handle(62..64) can appear at startup/menu
    // and produce early phantom subtitles before in-game dialogue.
    return (handle >= 62 && handle <= 64);
}

static inline bool IsSafeUnlockTrackNonStreamHandle(int handle) {
    if (handle <= 0) {
        return false;
    }
    // In tokenized MMFS2->DSOUND chains, allow any validated dialogue handle.
    // This keeps non-stream dialogue deterministic without brittle name-only whitelists.
    if (IsDialogHandleValue(handle)) {
        return true;
    }
    // Legacy fallback (early startup/probe) if subtitle tables are not fully ready.
    auto it = g_sound_name_map.find(handle);
    if (it == g_sound_name_map.end()) {
        return false;
    }
    std::string n = it->second;
    for (size_t i = 0; i < n.size(); i++) {
        unsigned char c = static_cast<unsigned char>(n[i]);
        if (c >= 'A' && c <= 'Z') {
            n[i] = static_cast<char>(c - 'A' + 'a');
        }
    }
    if (n.find("handunit") != std::string::npos ||
        n.find("denied") != std::string::npos ||
        n.find("granted") != std::string::npos) {
        return true;
    }
    return false;
}
static inline bool IsFp1RawCandidateId(int v) {
    switch (v) {
    case 96:
    case 117:
    case 129:
    case 186:
    case 190:
    case 202:
    case 236:
        return true;
    default:
        return false;
    }
}

static inline bool IsFp1CanonicalCandidateId(int v) {
    switch (v) {
    case 97:
    case 118:
    case 130:
    case 187:
    case 191:
    case 203:
    case 237:
        return true;
    default:
        return false;
    }
}

static inline bool ShouldLogFp1KeyLine(int raw_id, int canonical_id) {
    // For one-run forensic capture, allow broad key-line logging under probe_mode so
    // we can continue offline/static reasoning from a single runtime trace.
    if (g_probe_mode) {
        if (raw_id > 0 || canonical_id > 0) {
            return true;
        }
    }
    return IsFp1RawCandidateId(raw_id) || IsFp1CanonicalCandidateId(canonical_id);
}

static inline void SetOrd61StreamHint(int handle, DWORD tick, unsigned short ord) {
    if (handle <= 0) {
        return;
    }
    unsigned long long v = (static_cast<unsigned long long>(tick) << 32) |
                           static_cast<unsigned long long>(static_cast<unsigned int>(handle));
    g_last_ord61_stream_hint_ord.store(ord, std::memory_order_relaxed);
    g_last_ord61_stream_hint64.store(v, std::memory_order_relaxed);
}

static bool HasRecentOrd61StreamHintForHandle(DWORD now, int handle, DWORD window_ms) {
    if (handle <= 0) {
        return false;
    }
    unsigned long long v = g_last_ord61_stream_hint64.load(std::memory_order_relaxed);
    if (v == 0) {
        return false;
    }
    DWORD tick = static_cast<DWORD>(v >> 32);
    int h = static_cast<int>(static_cast<unsigned int>(v & 0xFFFFFFFFULL));
    if (h <= 0 || h != handle) {
        return false;
    }
    // Accept only ord61-family sources.
    // ord74/ord187 can mention handle=97 in non-dialogue contexts and must not qualify as ord61 evidence.
    unsigned short src_ord = g_last_ord61_stream_hint_ord.load(std::memory_order_relaxed);
    if (src_ord != 61 && src_ord != kPseudoOrdFun12b50) {
        return false;
    }
    return (now - tick) <= window_ms;
}

static inline bool ShouldApplyStreamExpectedHint(int handle, const WAVEFORMATEX &wfx, DWORD target_bytes) {
    if (!IsAutoStreamHintSeedHandle(handle)) {
        return false;
    }
    // Only apply when the DirectSound buffer looks like the engine's streaming ring-buffer for voice:
    // mono, s16, 44.1/48k, and ~1.2 seconds worth of PCM. This mitigates ord786 noise.
    if (wfx.nChannels != 1 || wfx.wBitsPerSample != 16) {
        return false;
    }
    if (wfx.nSamplesPerSec != 44100 && wfx.nSamplesPerSec != 48000) {
        return false;
    }
    const DWORD bytes_per_sec = static_cast<DWORD>(wfx.nSamplesPerSec) * static_cast<DWORD>(wfx.nChannels) *
                                static_cast<DWORD>(wfx.wBitsPerSample / 8);
    if (bytes_per_sec == 0) {
        return false;
    }
    // 1.2s ring-buffer: bytes_per_sec * 6/5
    const DWORD want = (bytes_per_sec * 6) / 5;
    const DWORD kTol = 8;
    if (target_bytes + kTol < want || target_bytes > want + kTol) {
        return false;
    }
    return true;
}

static inline bool LooksLikeVoiceRingBuffer(const WAVEFORMATEX &wfx, DWORD target_bytes) {
    // NOTE: keep this in sync with ShouldApplyStreamExpectedHint() (but without requiring a handle).
    if (wfx.nChannels != 1 || wfx.wBitsPerSample != 16) {
        return false;
    }
    if (wfx.nSamplesPerSec != 44100 && wfx.nSamplesPerSec != 48000) {
        return false;
    }
    const DWORD bytes_per_sec = static_cast<DWORD>(wfx.nSamplesPerSec) * static_cast<DWORD>(wfx.nChannels) *
                                static_cast<DWORD>(wfx.wBitsPerSample / 8);
    if (bytes_per_sec == 0) {
        return false;
    }
    // 1.2s ring-buffer: bytes_per_sec * 6/5
    const DWORD want = (bytes_per_sec * 6) / 5;
    const DWORD kTol = 8;
    if (target_bytes + kTol < want || target_bytes > want + kTol) {
        return false;
    }
    return true;
}

static inline void SetGlobalStreamExpectedHint(int handle, DWORD tick, unsigned short ord,
                                               unsigned long long episode_key = 0ULL) {
    if (handle <= 0) {
        return;
    }
    const unsigned long long prev_v = g_last_stream_expected_hint64.load(std::memory_order_relaxed);
    const int prev_handle = static_cast<int>(static_cast<unsigned int>(prev_v & 0xFFFFFFFFULL));
    const unsigned short prev_ord = g_last_stream_expected_hint_ord.load(std::memory_order_relaxed);

    // Accept only canonical play-root sources for stream expected-hints.
    // This prevents noisy ordinals (e.g. ord61/ord74/ord187/ord786) from overwriting the hint.
    if (ord != 1077 && ord != 190 && ord != 388) {
        if (g_probe_mode && IsStreamExpectedHintHandle(handle)) {
            static LONG s_stream_hint_reject_logs = 0;
            LONG n = InterlockedIncrement(&s_stream_hint_reject_logs);
            if (g_ultra_log || n <= 400) {
                std::ostringstream oss;
                oss << "STREAM_HINT_REJECT handle=" << handle
                    << " ord=" << ord
                    << " prev_h=" << prev_handle
                    << " prev_ord=" << prev_ord
                    << " reason=non_canonical_ord";
                LogLine(oss.str().c_str());
            }
        }
        return;
    }
    unsigned long long v = (static_cast<unsigned long long>(tick) << 32) |
                           static_cast<unsigned long long>(static_cast<unsigned int>(handle));
    g_last_stream_expected_hint_ord.store(ord, std::memory_order_relaxed);
    g_last_stream_expected_hint_token.store(episode_key, std::memory_order_relaxed);
    g_last_stream_expected_hint64.store(v, std::memory_order_relaxed);
    StreamDiagRecordHintSet(handle);
    if (g_probe_mode && (prev_handle != handle || prev_ord != ord)) {
        static LONG s_stream_hint_set_logs = 0;
        LONG n = InterlockedIncrement(&s_stream_hint_set_logs);
        if (g_ultra_log || n <= 1200) {
            std::ostringstream oss;
                oss << "STREAM_HINT_SET handle=" << handle
                    << " ord=" << ord
                    << " token=0x" << std::hex << episode_key << std::dec
                    << " prev_h=" << prev_handle
                    << " prev_ord=" << prev_ord
                << " stream_class=" << (IsStreamExpectedHintHandle(handle) ? 1 : 0)
                << " auto_seed=" << (IsAutoStreamHintSeedHandle(handle) ? 1 : 0)
                << " dialog_class=" << (IsDialogHandleValue(handle) ? 1 : 0);
            LogLine(oss.str().c_str());
        }
    }
}

static bool PeekRawGlobalStreamExpectedHint(int *out_handle,
                                            unsigned short *out_ord,
                                            DWORD *out_tick,
                                            unsigned long long *out_token) {
    if (!out_handle) {
        return false;
    }
    unsigned long long v = g_last_stream_expected_hint64.load(std::memory_order_relaxed);
    if (v == 0) {
        return false;
    }
    DWORD tick = static_cast<DWORD>(v >> 32);
    int handle = static_cast<int>(static_cast<unsigned int>(v & 0xFFFFFFFFULL));
    if (handle <= 0) {
        return false;
    }
    *out_handle = handle;
    if (out_ord) {
        *out_ord = g_last_stream_expected_hint_ord.load(std::memory_order_relaxed);
    }
    if (out_tick) {
        *out_tick = tick;
    }
    if (out_token) {
        *out_token = g_last_stream_expected_hint_token.load(std::memory_order_relaxed);
    }
    return true;
}

static bool PeekGlobalStreamExpectedHint(DWORD now,
                                         int *out_handle,
                                         unsigned short *out_ord,
                                         DWORD *out_tick,
                                         unsigned long long *out_token = nullptr);

static bool HasRecentTrustedStreamExpectedHintForHandle(DWORD now, int handle, DWORD window_ms) {
    if (handle <= 0) {
        return false;
    }
    int sh = 0;
    unsigned short shord = 0;
    DWORD shtick = 0;
    if (!PeekGlobalStreamExpectedHint(now, &sh, &shord, &shtick)) {
        return false;
    }
    if (sh != handle || sh <= 0) {
        return false;
    }
    if ((now - shtick) > window_ms) {
        return false;
    }
    return (shord == 1077 || shord == 190 || shord == 388);
}

static bool PeekGlobalStreamExpectedHint(DWORD now,
                                         int *out_handle,
                                         unsigned short *out_ord,
                                         DWORD *out_tick,
                                         unsigned long long *out_token) {
    if (!out_handle) {
        return false;
    }
    unsigned long long v = g_last_stream_expected_hint64.load(std::memory_order_relaxed);
    if (v == 0) {
        return false;
    }
    DWORD tick = static_cast<DWORD>(v >> 32);
    int handle = static_cast<int>(static_cast<unsigned int>(v & 0xFFFFFFFFULL));
    if (handle <= 0) {
        return false;
    }
    if ((now - tick) > kStreamExpectedHintWindowMs) {
        return false;
    }
    *out_handle = handle;
    if (out_ord) {
        *out_ord = g_last_stream_expected_hint_ord.load(std::memory_order_relaxed);
    }
    if (out_tick) {
        *out_tick = tick;
    }
    if (out_token) {
        *out_token = g_last_stream_expected_hint_token.load(std::memory_order_relaxed);
    }
    return true;
}

static inline bool IsCanonicalStreamHintOrd(unsigned short ord) {
    return (ord == 1077 || ord == 190 || ord == 388);
}

static inline bool ShouldUseNoHashStreamCapture(int expected_handle,
                                                 unsigned short expected_ord,
                                                 unsigned long long expected_token,
                                                 const WAVEFORMATEX &wfx,
                                                 DWORD target_bytes) {
    if (expected_handle <= 0) {
        return false;
    }
    // Keep no-hash mode very narrow.
    // Broad no-hash behavior turns stream matching into hint-only behavior and causes
    // misses after the first matched line. We reserve no-hash for the historically unstable
    // Baby01 lane and keep all other stream lanes in deterministic hash/progressive-hash paths.
    if (!IsStreamExpectedHintHandle(expected_handle)) {
        return false;
    }
    if (expected_handle != 97) {
        return false;
    }
    return LooksLikeVoiceRingBuffer(wfx, target_bytes);
}

static bool ConsumeGlobalStreamExpectedHint(DWORD now, int *out_handle, unsigned short *out_ord) {
    if (!out_handle) {
        return false;
    }
    for (int i = 0; i < 3; i++) {
        unsigned long long v = g_last_stream_expected_hint64.load(std::memory_order_relaxed);
        if (v == 0) {
            return false;
        }
        DWORD tick = static_cast<DWORD>(v >> 32);
        int handle = static_cast<int>(static_cast<unsigned int>(v & 0xFFFFFFFFULL));
        if (handle <= 0) {
            return false;
        }
        if ((now - tick) > kStreamExpectedHintWindowMs) {
            return false;
        }
        unsigned long long expected = v;
        if (g_last_stream_expected_hint64.compare_exchange_strong(expected, 0ULL, std::memory_order_relaxed)) {
            g_last_stream_expected_hint_token.store(0ULL, std::memory_order_relaxed);
            *out_handle = handle;
            if (out_ord) {
                *out_ord = g_last_stream_expected_hint_ord.load(std::memory_order_relaxed);
            }
            return true;
        }
    }
    return false;
}

