static void StreamDiagRecordCaptureLifecycle(const char *event,
                                             int expected_handle,
                                             const char *reason,
                                             unsigned long long bytes,
                                             DWORD target_bytes,
                                             bool has_expected_token) {
    if (!StreamDiagEnabled() || !event) {
        return;
    }
    std::lock_guard<std::mutex> lock(g_stream_diag_mu);
    if (strcmp(event, "STREAM_CAPTURE_CLEAR") == 0) {
        g_stream_diag_state.cap_clear++;
        if (reason && _stricmp(reason, "buffer_stop") == 0) {
            g_stream_diag_state.cap_clear_buffer_stop++;
        } else if (reason && _stricmp(reason, "play_restart") == 0) {
            g_stream_diag_state.cap_clear_play_restart++;
        } else if (reason && _stricmp(reason, "unlock_hash_resolved") == 0) {
            g_stream_diag_state.cap_clear_hash_resolved++;
        } else {
            g_stream_diag_state.cap_clear_other++;
        }
        if (target_bytes > 0) {
            const unsigned long long fill_pm = (bytes * 1000ULL) / static_cast<unsigned long long>(target_bytes);
            if (fill_pm < 100ULL) {
                g_stream_diag_state.cap_clear_fill_lt_10++;
            } else if (fill_pm < 500ULL) {
                g_stream_diag_state.cap_clear_fill_10_50++;
            } else {
                g_stream_diag_state.cap_clear_fill_ge_50++;
            }
        }
        if (has_expected_token) {
            g_stream_diag_state.cap_clear_token_nonzero++;
        } else {
            g_stream_diag_state.cap_clear_token_zero++;
        }
    } else if (strcmp(event, "STREAM_CAPTURE_DROP") == 0) {
        g_stream_diag_state.cap_drop++;
        if (reason && (_stricmp(reason, "timeout_or_gap") == 0 ||
                       _stricmp(reason, "already_full_reset") == 0)) {
            g_stream_diag_state.cap_drop_timeout_gap++;
        } else if (reason && _stricmp(reason, "no_hash_timeout_or_gap") == 0) {
            g_stream_diag_state.cap_drop_nohash_timeout_gap++;
        } else {
            g_stream_diag_state.cap_drop_other++;
        }
    }
    StreamDiagBumpHandle(&g_stream_diag_state.capture_by_handle, expected_handle);
}

