static void LogProbeHandle(unsigned short ord, int arg, int handle, DWORD ecx, DWORD edx) {
    std::wstring dir = GetGameDirW();
    if (dir.empty()) {
        return;
    }
    std::wstring file = dir + L"\\mmfs2_handle_calls.tsv";
    std::ofstream out(file.c_str(), std::ios::out | std::ios::app | std::ios::binary);
    if (!out.is_open()) {
        return;
    }
    DWORD now = GetTickCount();
    char line[256];
    sprintf(line, "%u\t%u\t%d\t%d\t%u\t%u\n",
            (unsigned int)now,
            (unsigned int)ord,
            arg,
            handle,
            (unsigned int)ecx,
            (unsigned int)edx);
    out.write(line, strlen(line));
}

struct SubtitleEntry {
    COLORREF color;
    double duration;
    std::vector<std::wstring> sentences;
    std::wstring speaker;  // Extracted from first sentence or [tag]
};

static bool IsSoundOnly(const SubtitleEntry &entry) {
    if (entry.sentences.empty()) {
        return false;
    }
    auto is_sound_tag = [](const std::wstring &s) -> bool {
        size_t i = 0;
        while (i < s.size() && iswspace(s[i])) {
            i++;
        }
        if (i >= s.size() || s[i] != L'[') {
            return false;
        }
        size_t r = s.find(L']', i + 1);
        if (r == std::wstring::npos) {
            return false;
        }
        std::wstring tag = s.substr(i + 1, r - (i + 1));
        std::wstring compact;
        compact.reserve(tag.size());
        for (wchar_t c : tag) {
            if (!iswspace(c)) {
                compact.push_back(c);
            }
        }
        if (compact == L"\xC18C\xB9AC") { // "�Ҹ�"
            return true;
        }
        if (compact == L"\xD6A8\xACFC\xC74C") { // "ȿ����"
            return true;
        }
        if (compact == L"SFX" || compact == L"sfx") {
            return true;
        }
        if (compact == L"SOUND" || compact == L"sound") {
            return true;
        }
        return false;
    };
    for (const auto &s : entry.sentences) {
        if (!is_sound_tag(s)) {
            return false;
        }
    }
    return true;
}

