static void RememberObjHandle(DWORD obj, int handle) {
    if (obj < 0x10000 || handle <= 0) {
        return;
    }
    std::lock_guard<std::mutex> lock(g_obj_handle_mutex);
    g_obj_handle_map[obj] = handle;
    if (g_obj_handle_map.size() > 4096) {
        g_obj_handle_map.clear();
    }
}

static bool LookupObjHandle(DWORD obj, int *out_handle) {
    if (obj < 0x10000 || !out_handle) {
        return false;
    }
    std::lock_guard<std::mutex> lock(g_obj_handle_mutex);
    auto it = g_obj_handle_map.find(obj);
    if (it == g_obj_handle_map.end()) {
        return false;
    }
    *out_handle = it->second;
    return true;
}

