static bool IsHandleKnown(int v) {
    if (g_handle_subs.find(v) != g_handle_subs.end()) {
        return true;
    }
    // Name-based subtitles (subtitles_by_name.txt) must also mark handles as known.
    // Otherwise, dialogue that only exists in the name table (e.g., Baby01) will never
    // be considered a valid handle candidate in MMFS2 scans when DSOUND gating is enabled.
    if (FindSubtitleEntryForHandle(v) != NULL) {
        return true;
    }
    if (!g_use_dsound_trigger) {
        return g_sound_name_map.find(v) != g_sound_name_map.end();
    }
    return false;
}

// Resolve a subtitle entry for a handle from either handle-based subs or name-based subs
// via sound_names.csv (handle -> name). This is important because many dialogue lines
// are maintained in subtitles_by_name.txt only.
static SubtitleEntry *FindSubtitleEntryForHandle(int handle) {
    auto hit = g_handle_subs.find(handle);
    if (hit != g_handle_subs.end()) {
        return &hit->second;
    }
    auto itn = g_sound_name_map.find(handle);
    if (itn == g_sound_name_map.end()) {
        return NULL;
    }
    const std::string &name = itn->second;
    auto nit = g_name_subs.find(name);
    if (nit != g_name_subs.end()) {
        return &nit->second;
    }
    std::string norm = NormalizeName(name);
    if (!norm.empty()) {
        auto nnit = g_name_subs_norm.find(norm);
        if (nnit != g_name_subs_norm.end()) {
            return &nnit->second;
        }
    }
    return NULL;
}

static const char *ResolveSubtitlePathForHandleValue(int handle) {
    if (g_handle_subs.find(handle) != g_handle_subs.end()) {
        return "by-handle";
    }
    if (FindSubtitleEntryForHandle(handle) != NULL) {
        return "by-name";
    }
    return "unknown";
}

static bool ResolveHandleForSubtitleEntryPtr(const SubtitleEntry *entry, int *out_handle, const char **out_path) {
    if (!entry || !out_handle) {
        return false;
    }
    for (const auto &kv : g_handle_subs) {
        if (&kv.second == entry) {
            *out_handle = kv.first;
            if (out_path) {
                *out_path = "by-handle";
            }
            return true;
        }
    }
    for (const auto &kv : g_sound_name_map) {
        const int h = kv.first;
        SubtitleEntry *resolved = FindSubtitleEntryForHandle(h);
        if (resolved == entry) {
            *out_handle = h;
            if (out_path) {
                *out_path = ResolveSubtitlePathForHandleValue(h);
            }
            return true;
        }
    }
    return false;
}

static void LogSubTriggerForCandidate(int handle, const char *path) {
    if (handle <= 0 || !ShouldLogFp1KeyLine(handle, handle)) {
        return;
    }
    static LONG s_sub_trigger_logs = 0;
    LONG n = InterlockedIncrement(&s_sub_trigger_logs);
    if (n > 400) {
        return;
    }
    std::ostringstream oss;
    oss << "SUB_TRIGGER handle=" << handle
        << " path=" << (path ? path : "unknown")
        << " stream_expected=" << (IsStreamExpectedHintHandle(handle) ? 1 : 0);
    LogLine(oss.str().c_str());
    AppendForensicEvent("SUB_TRIGGER", handle, handle, 0,
                        0, 0, 0, 0, 0, 0, 0,
                        (path ? path : "unknown"));
}

static void LogMatchCandidate(const char *source,
                              void *buf,
                              int handle,
                              unsigned int generation,
                              const char *note) {
    if (handle <= 0) {
        return;
    }
    if (!g_audio_test_mode && !g_probe_mode) {
        return;
    }
    static LONG s_match_cand_logs = 0;
    LONG n = InterlockedIncrement(&s_match_cand_logs);
    if (!g_ultra_log && n > 3000) {
        return;
    }
    std::ostringstream oss;
    oss << "MATCH_CANDIDATE src=" << (source ? source : "unknown")
        << " handle=" << handle
        << " gen=" << generation
        << " buf=0x" << std::hex << reinterpret_cast<uintptr_t>(buf) << std::dec;
    if (note && note[0]) {
        oss << " note=" << note;
    }
    LogLine(oss.str().c_str());
}

static void LogMatchConfirmed(const char *source,
                              void *buf,
                              int handle,
                              unsigned int generation,
                              bool resolved_from_region,
                              const HashInfo *info) {
    if (handle <= 0) {
        return;
    }
    // Runtime-confirmed sweep accounting must run even when match logs are rate-limited.
    SweepRuntimeTrackConfirmed(source, buf, handle, generation, resolved_from_region, info);

    static LONG s_match_confirm_logs = 0;
    LONG n = InterlockedIncrement(&s_match_confirm_logs);
    if (!g_ultra_log && n > 5000) {
        return;
    }
    std::ostringstream oss;
    oss << "MATCH_CONFIRMED src=" << (source ? source : "unknown")
        << " handle=" << handle
        << " gen=" << generation
        << " buf=0x" << std::hex << reinterpret_cast<uintptr_t>(buf) << std::dec
        << " region=" << (resolved_from_region ? 1 : 0);
    if (info && info->valid) {
        oss << " hash=0x" << std::hex << info->hash << std::dec
            << " bytes=" << info->bytes
            << " rate=" << info->rate
            << " ch=" << info->channels
            << " bits=" << info->bits;
    }
    LogLine(oss.str().c_str());
}
static bool IsDialogueEntry(const SubtitleEntry &entry) {
    if (entry.sentences.empty()) {
        return false;
    }

    auto is_bracket_sfx_tag = [](const std::wstring &speaker) -> bool {
        size_t l = speaker.find(L'[');
        if (l == std::wstring::npos) {
            return false;
        }
        size_t r = speaker.find(L']', l + 1);
        if (r == std::wstring::npos || r <= l + 1) {
            return false;
        }
        std::wstring tag = speaker.substr(l + 1, r - (l + 1));
        // trim whitespace
        size_t a = 0;
        while (a < tag.size() && iswspace(tag[a])) a++;
        size_t b = tag.size();
        while (b > a && iswspace(tag[b - 1])) b--;
        tag = (b > a) ? tag.substr(a, b - a) : L"";

        // Korean tags
        if (tag == L"\xC18C\xB9AC" || // "�Ҹ�"
            tag == L"\xD6A8\xACFC\xC74C" || // "ȿ����"
            tag == L"\xC74C\xD5A5\xD6A8\xACFC" || // "����ȿ��"
            tag == L"\xBC30\xACBD\xC74C" || // "�����"
            tag == L"\xC74C\xC545") { // "����"
            return true;
        }

        // English tags
        if (tag == L"SFX" || tag == L"sfx" || tag == L"SE" || tag == L"se") {
            return true;
        }
        if (tag == L"SOUND" || tag == L"sound") {
            return true;
        }
        return false;
    };
    
    // Check the extracted speaker field
    if (!entry.speaker.empty()) {
        // Bracket tags can be either SFX ([...]) or spoken system voices ([...]).
        // Only treat them as non-dialogue when they're a known SFX/music tag.
        if (entry.speaker.find(L"[") != std::wstring::npos) {
            return !is_bracket_sfx_tag(entry.speaker);
        }
        // eumak, baegyeonggeum, annaegeum, hyokwageum
        if (entry.speaker == L"\xC74C\xC545:" || entry.speaker == L"\xC74C\xC545") return false;  // "����:" or "����"
        if (entry.speaker == L"\xBC30\xACBD\xC74C" || entry.speaker == L"\xBC30\xACBD\xC74C:") return false;  // "�����" or "�����:"
        if (entry.speaker == L"\xD6A8\xACFC\xC74C" || entry.speaker == L"\xD6A8\xACFC\xC74C:") return false;  // "ȿ����" or "ȿ����:"
        if (entry.speaker == L"\xC18C\xB9AC" || entry.speaker == L"\xC18C\xB9AC:") return false;  // "�Ҹ�" or "�Ҹ�:"
    }
    
    // If we don't have a speaker tag, treat as dialogue (mobile/handle-based lines).
    if (entry.speaker.empty()) {
        return true;
    }

    auto is_non_dialog_speaker = [&](const std::wstring &speaker) -> bool {
        if (speaker.empty()) {
            return true;
        }
        // Bracket tags like [�Ҹ�], [����], [�����]
        if (speaker.find(L"[") != std::wstring::npos || speaker.find(L"]") != std::wstring::npos) {
            return is_bracket_sfx_tag(speaker);
        }
        
        // Exact match only for non-dialogue speakers
        // �����: background music/sound
        if (speaker == L"\xBC30\xACBD\xC74C" || speaker == L"\xBC30\xACBD") { // "�����" or "���"
            return true;
        }
        // ����: music
        if (speaker == L"\xC74C\xC545" || speaker == L"\xC74C\xC545:") { // "����"
            return true;
        }
        // ȿ����/�Ҹ�/SFX/SE: sound effects (multiple variations)
        if (speaker == L"\xD6A8\xACFC\xC74C" || speaker == L"\xD6A8\xACFC" || // "ȿ����" or "ȿ��"
            speaker == L"\xC18C\xB9AC" || speaker == L"\xC18C\xB9AC:" || // "�Ҹ�" or "�Ҹ�:"
            speaker == L"SFX" || speaker == L"SE" || // English abbreviations
            speaker == L"SE:" || speaker == L"SFX:") { // With colon
            return true;
        }
        // ����ȿ��: sound effect (alternative term)
        if (speaker == L"\xC74C\xD5A5\xD6A8\xACFC" || speaker == L"\xC74C\xD5A5\xD6A8\xACFC:") { // "����ȿ��" or "����ȿ��:"
            return true;
        }
        // Silence/Pause markers
        if (speaker == L"\xBB35\xC74C" || // "����"
            speaker == L"\xC911\xB2E8") { // "�ߴ�"
            return true;
        }
        
        return false;
    };
    for (const auto &s : entry.sentences) {
        size_t pos = s.find(L":");
        if (pos == std::wstring::npos) {
            pos = s.find(L"\xFF1A"); // '��'
        }
        if (pos == std::wstring::npos) {
            continue;
        }
        std::wstring speaker = s.substr(0, pos);
        // trim
        size_t a = 0;
        while (a < speaker.size() && iswspace(speaker[a])) a++;
        size_t b = speaker.size();
        while (b > a && iswspace(speaker[b - 1])) b--;
        if (b > a) {
            speaker = speaker.substr(a, b - a);
        } else {
            speaker.clear();
        }
        if (!is_non_dialog_speaker(speaker)) {
            return true;
        }
    }
    return false;
}

static bool IsDialogHandle(int v) {
    if (HasMobileDialogHandle(v)) {
        return true;
    }
    SubtitleEntry *entry = FindSubtitleEntryForHandle(v);
    if (!entry) {
        return false;
    }
    if (IsSoundOnly(*entry)) {
        return false;
    }
    if (g_dialogue_only && !IsDialogueEntry(*entry)) {
        return false;
    }
    return true;
}

static bool IsDialogHandleValue(int v) {
    if (v < 0 || v > g_handle_max) {
        return false;
    }
    // Don't let the (optional) mobile subtitle set influence handle classification unless we're
    // actually using mobile subs. Otherwise it pollutes dialog detection and causes false matches.
    if (!g_disable_mobile_subs && HasMobileDialogHandle(v)) {
        return true;
    }
    SubtitleEntry *entry = FindSubtitleEntryForHandle(v);
    if (!entry) {
        return false;
    }
    if (IsSoundOnly(*entry)) {
        return false;
    }
    if (g_dialogue_only && !IsDialogueEntry(*entry)) {
        return false;
    }
    return true;
}

// MMFS2 by-id values can be in a different basis than subtitle/sound-name tables in some paths.
// Keep slot matching on raw ids, but normalize into canonical handle-space for subtitle/hint use.
static int NormalizeMmfs2ByIdToHandle(int raw_id, unsigned short src_ord, bool *shifted = nullptr) {
    if (shifted) {
        *shifted = false;
    }
    if (raw_id <= 0) {
        return raw_id;
    }
    const int plus = raw_id + 1;
    const bool fp1_candidate = IsFp1RawCandidateId(raw_id) || IsFp1CanonicalCandidateId(plus);
    auto log_decision = [&](const char *reason,
                            int out_id,
                            bool did_shift,
                            SubtitleEntry *raw_entry,
                            SubtitleEntry *plus_entry,
                            bool raw_is_dialog,
                            bool plus_is_dialog) {
        if (!fp1_candidate) {
            return;
        }
        static LONG s_norm_decision_log = 0;
        LONG n = InterlockedIncrement(&s_norm_decision_log);
        if (n > 800) {
            return;
        }
        std::ostringstream oss;
        oss << "MMFS2_ID_NORMALIZE_DECISION ord=" << src_ord
            << " raw=" << raw_id
            << " plus=" << plus
            << " out=" << out_id
            << " shifted=" << (did_shift ? 1 : 0)
            << " reason=" << (reason ? reason : "unknown")
            << " raw_entry=" << (raw_entry ? 1 : 0)
            << " plus_entry=" << (plus_entry ? 1 : 0)
            << " raw_dialog=" << (raw_is_dialog ? 1 : 0)
            << " plus_dialog=" << (plus_is_dialog ? 1 : 0);
        LogLine(oss.str().c_str());
    };
    if (plus <= 0 || plus > g_handle_max) {
        log_decision("plus_out_of_range", raw_id, false, NULL, NULL, false, false);
        return raw_id;
    }
    // Keep normalization conservative:
    // only shift into known stream-expected handles (Baby-family class), and only when the raw handle
    // is not already stream-expected.
    // Control-domain normalization must stay on the conservative core stream class.
    // Using dynamic stream lanes here over-promotes raw SFX ids into dialogue handles.
    if (!IsLegacyCoreStreamExpectedHandle(plus) || IsLegacyCoreStreamExpectedHandle(raw_id)) {
        log_decision("stream_expected_gate", raw_id, false, NULL, NULL, false, false);
        return raw_id;
    }
    SubtitleEntry *plus_entry = FindSubtitleEntryForHandle(plus);
    const bool plus_is_dialog = (plus_entry && !IsSoundOnly(*plus_entry) &&
                                 (!g_dialogue_only || IsDialogueEntry(*plus_entry)));
    if (!plus_entry || !plus_is_dialog) {
        log_decision("plus_not_dialogue", raw_id, false, NULL, plus_entry, false, plus_is_dialog);
        return raw_id;
    }
    SubtitleEntry *raw_entry = FindSubtitleEntryForHandle(raw_id);
    const bool raw_is_dialog = (raw_entry && !IsSoundOnly(*raw_entry) &&
                                (!g_dialogue_only || IsDialogueEntry(*raw_entry)));
    if (raw_is_dialog) {
        log_decision("raw_is_dialog", raw_id, false, raw_entry, plus_entry, raw_is_dialog, plus_is_dialog);
        return raw_id;
    }
    if (shifted) {
        *shifted = true;
    }
    log_decision("shift_to_plus", plus, true, raw_entry, plus_entry, raw_is_dialog, plus_is_dialog);
    if (g_probe_mode) {
        static int s_norm_log = 0;
        if (s_norm_log < 200) {
            std::ostringstream oss;
            oss << "MMFS2_ID_NORMALIZE ord=" << src_ord
                << " raw=" << raw_id
                << " canonical=" << plus;
            LogLine(oss.str().c_str());
            s_norm_log++;
        }
    }
    return plus;
}

// Ord1077/190 control-domain ids (1..41) can represent dialogue handles in a shifted subtitle space.
// Keep this fallback narrow: only when raw id has no dialogue entry and shifted id does.
static int TryResolveControlDomainHandle(int raw_id, unsigned short src_ord) {
    if (src_ord != 1077 && src_ord != 190) {
        return -1;
    }
    if (raw_id <= 0 || raw_id > 41) {
        return -1;
    }
    // Control-domain ids are compact (1..41); subtitle/dialog handle-space is shifted in this path.
    const int shifted = raw_id + 61;
    // Keep +61 control fallback conservative (core stream class only).
    if (!IsDialogHandleValue(shifted) && !IsLegacyCoreStreamExpectedHandle(shifted)) {
        return -1;
    }
    return shifted;
}

static std::string DescribeStaticHandleForLog(int handle) {
    std::ostringstream oss;
    oss << "h=" << handle;
    if (handle <= 0) {
        return oss.str();
    }
    auto itn = g_sound_name_map.find(handle);
    if (itn != g_sound_name_map.end() && !itn->second.empty()) {
        oss << " name=" << itn->second;
    }
    SubtitleEntry *entry = FindSubtitleEntryForHandle(handle);
    oss << " entry=" << (entry ? 1 : 0)
        << " dlg=" << (IsDialogHandleValue(handle) ? 1 : 0)
        << " stream=" << (IsStreamExpectedHintHandle(handle) ? 1 : 0)
        << " auto_seed=" << (IsAutoStreamHintSeedHandle(handle) ? 1 : 0);
    return oss.str();
}

static void PruneEpisodeStaticRouteEvidenceLocked(DWORD now) {
    if (g_episode_static_route_by_token.size() > kEpisodeStaticRouteCap) {
        for (auto it = g_episode_static_route_by_token.begin();
             it != g_episode_static_route_by_token.end();) {
            if ((now - it->second.tick) > kEpisodeStaticRouteTtlMs) {
                it = g_episode_static_route_by_token.erase(it);
            } else {
                ++it;
            }
        }
        if (g_episode_static_route_by_token.size() > (kEpisodeStaticRouteCap * 2)) {
            g_episode_static_route_by_token.clear();
        }
    }
    if (g_episode_static_route_by_handle.size() > kEpisodeStaticRouteCap) {
        for (auto it = g_episode_static_route_by_handle.begin();
             it != g_episode_static_route_by_handle.end();) {
            if ((now - it->second.tick) > kEpisodeStaticRouteTtlMs) {
                it = g_episode_static_route_by_handle.erase(it);
            } else {
                ++it;
            }
        }
        if (g_episode_static_route_by_handle.size() > (kEpisodeStaticRouteCap * 2)) {
            g_episode_static_route_by_handle.clear();
        }
    }
}

static void RememberEpisodeStaticRouteEvidence(unsigned long long episode_key,
                                               DWORD now,
                                               unsigned short ord,
                                               int raw_id,
                                               int canonical_id,
                                               int control_id,
                                               DWORD flags,
                                               int slot,
                                               DWORD caller,
                                               bool by_name) {
    if (episode_key == 0ULL) {
        return;
    }
    EpisodeStaticRouteEvidence ev;
    ev.tick = now;
    ev.ord = ord;
    ev.raw_id = raw_id;
    ev.canonical_id = canonical_id;
    ev.control_id = control_id;
    ev.flags = flags;
    ev.slot = slot;
    ev.caller = caller;
    ev.by_name = by_name;

    std::lock_guard<std::mutex> lock(g_episode_static_route_mu);
    g_episode_static_route_by_token[episode_key] = ev;
    if (canonical_id > 0) {
        g_episode_static_route_by_handle[canonical_id] = ev;
    }
    if (control_id > 0) {
        g_episode_static_route_by_handle[control_id] = ev;
    }
    PruneEpisodeStaticRouteEvidenceLocked(now);
}

static bool ResolveEpisodeStaticRouteEvidence(unsigned long long episode_key,
                                              int expected_handle,
                                              DWORD now,
                                              EpisodeStaticRouteEvidence *out_ev,
                                              bool *out_token_exact = nullptr) {
    if (out_token_exact) {
        *out_token_exact = false;
    }
    if (!out_ev) {
        return false;
    }
    std::lock_guard<std::mutex> lock(g_episode_static_route_mu);
    if (episode_key != 0ULL) {
        auto it = g_episode_static_route_by_token.find(episode_key);
        if (it != g_episode_static_route_by_token.end() &&
            (now - it->second.tick) <= kEpisodeStaticRouteTtlMs) {
            *out_ev = it->second;
            if (out_token_exact) {
                *out_token_exact = true;
            }
            return true;
        }
    }
    if (expected_handle > 0) {
        auto it = g_episode_static_route_by_handle.find(expected_handle);
        if (it != g_episode_static_route_by_handle.end() &&
            (now - it->second.tick) <= kEpisodeStaticRouteHandleFallbackMs) {
            *out_ev = it->second;
            return true;
        }
    }
    return false;
}

static std::string DescribeEpisodeStaticRouteEvidenceForLog(unsigned long long episode_key,
                                                            int expected_handle,
                                                            DWORD now) {
    EpisodeStaticRouteEvidence ev;
    bool token_exact = false;
    if (!ResolveEpisodeStaticRouteEvidence(episode_key, expected_handle, now, &ev, &token_exact)) {
        return "none";
    }

    std::ostringstream oss;
    oss << "token_exact=" << (token_exact ? 1 : 0)
        << " age_ms=" << (now - ev.tick)
        << " ord=" << ev.ord
        << " raw_id=" << ev.raw_id
        << " slot=" << ev.slot
        << " flags=0x" << std::hex << ev.flags << std::dec
        << " by_name=" << (ev.by_name ? 1 : 0)
        << " caller=0x" << std::hex << ev.caller << std::dec
        << " canon={" << DescribeStaticHandleForLog(ev.canonical_id) << "}"
        << " control={" << DescribeStaticHandleForLog(ev.control_id) << "}";
    return oss.str();
}

static unsigned long long NextEpisodeUid() {
    unsigned long long uid = g_mmfs2_episode_uid_seq.fetch_add(1ULL, std::memory_order_relaxed);
    if (uid == 0ULL) {
        uid = g_mmfs2_episode_uid_seq.fetch_add(1ULL, std::memory_order_relaxed);
    }
    if (uid == 0ULL) {
        uid = 1ULL;
    }
    return uid;
}

static unsigned long long ComputeEpisodeAssetSig(int canonical_id, int raw_id) {
    // FNV-1a 64-bit over stable asset identity hints.
    unsigned long long h = 1469598103934665603ULL;
    auto mix_u64 = [&](unsigned long long v) {
        for (int i = 0; i < 8; ++i) {
            h ^= static_cast<unsigned char>((v >> (i * 8)) & 0xffULL);
            h *= 1099511628211ULL;
        }
    };
    auto mix_str = [&](const std::string &s) {
        for (char c : s) {
            h ^= static_cast<unsigned char>(c);
            h *= 1099511628211ULL;
        }
    };

    mix_u64(static_cast<unsigned long long>(static_cast<unsigned int>(canonical_id)));
    mix_u64(static_cast<unsigned long long>(static_cast<unsigned int>(raw_id)));
    if (canonical_id > 0) {
        auto itn = g_sound_name_map.find(canonical_id);
        if (itn != g_sound_name_map.end() && !itn->second.empty()) {
            mix_str(NormalizeName(itn->second));
        }
    }
    if (h == 0ULL) {
        h = 1ULL;
    }
    return h;
}

static void PruneEpisodeUidEvidenceLocked(DWORD now) {
    if (g_episode_uid_by_uid.size() <= kEpisodeUidCap &&
        g_episode_uid_from_token.size() <= (kEpisodeUidCap * 2) &&
        g_episode_uid_from_handle.size() <= (kEpisodeUidCap * 2)) {
        return;
    }

    std::unordered_set<unsigned long long> alive;
    for (auto it = g_episode_uid_by_uid.begin(); it != g_episode_uid_by_uid.end();) {
        if ((now - it->second.tick) > kEpisodeUidTtlMs) {
            it = g_episode_uid_by_uid.erase(it);
        } else {
            alive.insert(it->first);
            ++it;
        }
    }

    for (auto it = g_episode_uid_from_token.begin(); it != g_episode_uid_from_token.end();) {
        if (alive.find(it->second) == alive.end()) {
            it = g_episode_uid_from_token.erase(it);
        } else {
            ++it;
        }
    }
    for (auto it = g_episode_uid_from_handle.begin(); it != g_episode_uid_from_handle.end();) {
        if (alive.find(it->second) == alive.end()) {
            it = g_episode_uid_from_handle.erase(it);
        } else {
            ++it;
        }
    }

    if (g_episode_uid_by_uid.size() > (kEpisodeUidCap * 3)) {
        g_episode_uid_by_uid.clear();
        g_episode_uid_from_token.clear();
        g_episode_uid_from_handle.clear();
    }
}

static void RememberEpisodeUidEvidence(unsigned long long uid,
                                       unsigned long long token,
                                       unsigned long long episode_key,
                                       DWORD now,
                                       unsigned short ord,
                                       int raw_id,
                                       int canonical_id,
                                       int control_id,
                                       DWORD flags,
                                       int slot,
                                       DWORD caller,
                                       bool by_name) {
    if (uid == 0ULL) {
        return;
    }
    EpisodeUidEvidence ev;
    ev.tick = now;
    ev.ord = ord;
    ev.raw_id = raw_id;
    ev.canonical_id = canonical_id;
    ev.control_id = control_id;
    ev.flags = flags;
    ev.slot = slot;
    ev.caller = caller;
    ev.by_name = by_name;
    ev.token = token;
    ev.episode_key = episode_key;
    ev.uid = uid;
    ev.asset_sig = ComputeEpisodeAssetSig(canonical_id, raw_id);

    std::lock_guard<std::mutex> lock(g_episode_uid_mu);
    g_episode_uid_by_uid[uid] = ev;
    if (token != 0ULL) {
        g_episode_uid_from_token[token] = uid;
    }
    if (episode_key != 0ULL) {
        g_episode_uid_from_token[episode_key] = uid;
    }
    if (canonical_id > 0) {
        g_episode_uid_from_handle[canonical_id] = uid;
    }
    if (control_id > 0) {
        g_episode_uid_from_handle[control_id] = uid;
    }
    PruneEpisodeUidEvidenceLocked(now);
}

static bool ResolveEpisodeUidEvidenceByUid(unsigned long long uid,
                                           DWORD now,
                                           EpisodeUidEvidence *out_ev) {
    if (!out_ev || uid == 0ULL) {
        return false;
    }
    std::lock_guard<std::mutex> lock(g_episode_uid_mu);
    auto it = g_episode_uid_by_uid.find(uid);
    if (it == g_episode_uid_by_uid.end()) {
        return false;
    }
    if ((now - it->second.tick) > kEpisodeUidTtlMs) {
        return false;
    }
    *out_ev = it->second;
    return true;
}

static bool IsSubtitleEligibleHandleForCurrentFilters(int handle) {
    if (handle <= 0) {
        return false;
    }
    SubtitleEntry *entry = FindSubtitleEntryForHandle(handle);
    if (!entry) {
        return false;
    }
    if (!g_allow_sound_only && IsSoundOnly(*entry)) {
        return false;
    }
    if (g_dialogue_only && !IsDialogueEntry(*entry)) {
        return false;
    }
    return true;
}

static bool IsControlRoutePromotionFromNonSubtitleCanonical(const EpisodeStaticRouteEvidence &route_ev,
                                                            int target_handle) {
    if (target_handle <= 0) {
        return false;
    }
    if (route_ev.control_id <= 0 || route_ev.canonical_id <= 0) {
        return false;
    }
    if (route_ev.control_id != target_handle) {
        return false;
    }
    if (route_ev.canonical_id == target_handle) {
        return false;
    }
    if (IsSubtitleEligibleHandleForCurrentFilters(route_ev.canonical_id)) {
        return false;
    }
    // v25.8: keep this fail-close only for confirmed menu/control-noise pairs.
    // Broad suppression on all non-dialog canonical promotions blocked valid stream lines.
    const bool noise_pair_63 =
        (route_ev.control_id == 63 && route_ev.canonical_id == 2) ||
        (route_ev.control_id == 63 && route_ev.raw_id == 2);
    const bool noise_pair_64 =
        (route_ev.control_id == 64 && route_ev.canonical_id == 3) ||
        (route_ev.control_id == 64 && route_ev.raw_id == 3);
    return noise_pair_63 || noise_pair_64;
}

static inline bool IsStreamSourceHandleEligible(int handle);

static int ResolveStreamSourceHandleByTokenRoute(int input_handle,
                                                 unsigned long long token,
                                                 DWORD now,
                                                 EpisodeStaticRouteEvidence *out_route_ev,
                                                 bool *out_route_exact,
                                                 bool *out_promoted) {
    if (out_route_exact) {
        *out_route_exact = false;
    }
    if (out_promoted) {
        *out_promoted = false;
    }
    EpisodeStaticRouteEvidence route_ev;
    bool route_exact = false;
    const bool route_ok =
        (token != 0ULL) &&
        ResolveEpisodeStaticRouteEvidence(token, input_handle, now, &route_ev, &route_exact) &&
        route_exact;
    if (out_route_ev) {
        if (route_ok) {
            *out_route_ev = route_ev;
        } else {
            *out_route_ev = EpisodeStaticRouteEvidence();
        }
    }
    if (out_route_exact) {
        *out_route_exact = route_ok;
    }

    int resolved = input_handle;
    if (!IsStreamSourceHandleEligible(resolved) && route_ok) {
        if (route_ev.control_id > 0 &&
            IsStreamSourceHandleEligible(route_ev.control_id)) {
            resolved = route_ev.control_id;
        } else if (route_ev.canonical_id > 0 &&
                   IsStreamSourceHandleEligible(route_ev.canonical_id)) {
            resolved = route_ev.canonical_id;
        }
    }
    if (out_promoted) {
        *out_promoted = (resolved != input_handle);
    }
    return resolved;
}

static unsigned long long ResolveEpisodeUidByToken(unsigned long long token,
                                                   DWORD now,
                                                   EpisodeUidEvidence *out_ev = nullptr) {
    if (token == 0ULL) {
        return 0ULL;
    }
    std::lock_guard<std::mutex> lock(g_episode_uid_mu);
    auto it = g_episode_uid_from_token.find(token);
    if (it == g_episode_uid_from_token.end()) {
        return 0ULL;
    }
    auto iev = g_episode_uid_by_uid.find(it->second);
    if (iev == g_episode_uid_by_uid.end()) {
        return 0ULL;
    }
    if ((now - iev->second.tick) > kEpisodeUidTtlMs) {
        return 0ULL;
    }
    if (out_ev) {
        *out_ev = iev->second;
    }
    return iev->second.uid;
}

static unsigned long long ResolveEpisodeUidByHandle(int handle,
                                                    DWORD now,
                                                    EpisodeUidEvidence *out_ev = nullptr) {
    if (handle <= 0) {
        return 0ULL;
    }
    std::lock_guard<std::mutex> lock(g_episode_uid_mu);
    auto it = g_episode_uid_from_handle.find(handle);
    if (it == g_episode_uid_from_handle.end()) {
        return 0ULL;
    }
    auto iev = g_episode_uid_by_uid.find(it->second);
    if (iev == g_episode_uid_by_uid.end()) {
        return 0ULL;
    }
    if ((now - iev->second.tick) > kEpisodeUidHandleFallbackMs) {
        return 0ULL;
    }
    if (out_ev) {
        *out_ev = iev->second;
    }
    return iev->second.uid;
}

static std::string DescribeEpisodeUidEvidenceForLog(unsigned long long uid, DWORD now) {
    EpisodeUidEvidence ev;
    if (!ResolveEpisodeUidEvidenceByUid(uid, now, &ev)) {
        return "none";
    }
    std::ostringstream oss;
    oss << "age_ms=" << (now - ev.tick)
        << " uid=0x" << std::hex << ev.uid << std::dec
        << " ord=" << ev.ord
        << " raw_id=" << ev.raw_id
        << " slot=" << ev.slot
        << " flags=0x" << std::hex << ev.flags << std::dec
        << " by_name=" << (ev.by_name ? 1 : 0)
        << " token=0x" << std::hex << ev.token << std::dec
        << " episode_key=0x" << std::hex << ev.episode_key << std::dec
        << " asset_sig=0x" << std::hex << ev.asset_sig << std::dec
        << " caller=0x" << std::hex << ev.caller << std::dec
        << " canon={" << DescribeStaticHandleForLog(ev.canonical_id) << "}"
        << " control={" << DescribeStaticHandleForLog(ev.control_id) << "}";
    return oss.str();
}

static const DWORD kStreamSourceSeedTtlMs = 15000;
static const DWORD kStreamSourceSessionTtlMs = 20000;
static const DWORD kStreamSourceSeedBindWindowMs = 4000;
static const size_t kStreamSourceSeedCap = 8192;
static const size_t kStreamSourceSessionCap = 2048;
static const DWORD kStreamEpisodeTokenTtlMs = 1800000;
static const DWORD kPendingUnlockTrackMinBytes = 2048;

static inline bool IsStreamSourceHandleEligible(int handle) {
    // Keep this path strict to streamed dialogue lanes only.
    return IsStreamExpectedHintHandle(handle);
}

static void PruneStreamSourceStateLocked(DWORD now) {
    for (auto it = g_stream_source_seed_queue.begin(); it != g_stream_source_seed_queue.end();) {
        if ((now - it->tick) > kStreamSourceSeedTtlMs) {
            it = g_stream_source_seed_queue.erase(it);
        } else {
            ++it;
        }
    }
    if (g_stream_source_seed_queue.size() > (kStreamSourceSeedCap * 2)) {
        g_stream_source_seed_queue.clear();
    }
    for (auto it = g_stream_source_sessions.begin(); it != g_stream_source_sessions.end();) {
        if ((now - it->second.tick) > kStreamSourceSessionTtlMs) {
            it = g_stream_source_sessions.erase(it);
        } else {
            ++it;
        }
    }
    if (g_stream_source_sessions.size() > (kStreamSourceSessionCap * 2)) {
        g_stream_source_sessions.clear();
    }
}

static bool WasStreamEpisodeTokenFired(unsigned long long token, DWORD now, DWORD *out_age_ms = nullptr) {
    if (out_age_ms) {
        *out_age_ms = 0;
    }
    if (token == 0ULL) {
        return false;
    }
    std::lock_guard<std::mutex> lock(g_stream_episode_mu);
    auto it = g_stream_episode_fired_tick.find(token);
    if (it == g_stream_episode_fired_tick.end()) {
        return false;
    }
    const DWORD age = now - it->second;
    if (age > kStreamEpisodeTokenTtlMs) {
        g_stream_episode_fired_tick.erase(it);
        return false;
    }
    if (out_age_ms) {
        *out_age_ms = age;
    }
    return true;
}

static void MarkStreamEpisodeTokenFired(unsigned long long token, DWORD now) {
    if (token == 0ULL) {
        return;
    }
    std::lock_guard<std::mutex> lock(g_stream_episode_mu);
    g_stream_episode_fired_tick[token] = now;
    if (g_stream_episode_fired_tick.size() > 8192) {
        for (auto it = g_stream_episode_fired_tick.begin();
             it != g_stream_episode_fired_tick.end();) {
            if ((now - it->second) > kStreamEpisodeTokenTtlMs) {
                it = g_stream_episode_fired_tick.erase(it);
            } else {
                ++it;
            }
        }
        if (g_stream_episode_fired_tick.size() > 12288) {
            g_stream_episode_fired_tick.clear();
        }
    }
}

static void RememberStreamSourceSeed(unsigned short ord,
                                     int handle,
                                     int raw_id,
                                     int slot,
                                     DWORD flags,
                                     DWORD caller,
                                     unsigned long long token,
                                     unsigned long long uid,
                                     DWORD now,
                                     const char *reason) {
    if (token == 0ULL || handle <= 0 || !IsStreamSourceHandleEligible(handle)) {
        return;
    }
    EpisodeStaticRouteEvidence route_ev;
    bool token_exact = false;
    const bool route_ok = ResolveEpisodeStaticRouteEvidence(token, handle, now, &route_ev, &token_exact);
    if (!route_ok || !token_exact) {
        if (g_probe_mode) {
            static LONG s_seed_skip = 0;
            LONG n = InterlockedIncrement(&s_seed_skip);
            if (g_ultra_log || n <= 4000) {
                std::ostringstream oss;
                oss << "SRC_SEED_SKIP route_unqualified handle=" << handle
                    << " raw_id=" << raw_id
                    << " ord=" << ord
                    << " slot=" << slot
                    << " token=0x" << std::hex << token << std::dec
                    << " reason=" << (reason ? reason : "unknown");
                LogLine(oss.str().c_str());
            }
        }
        return;
    }

    StreamSourceSeed seed;
    seed.tick = now;
    seed.ord = ord;
    seed.handle = handle;
    seed.raw_id = raw_id;
    seed.slot = slot;
    seed.flags = flags;
    seed.caller = caller;
    seed.token = token;
    seed.uid = uid;

    {
        std::lock_guard<std::mutex> lock(g_stream_source_mu);
        PruneStreamSourceStateLocked(now);
        bool updated = false;
        for (auto &it : g_stream_source_seed_queue) {
            if (it.token == token) {
                it = seed;
                updated = true;
                break;
            }
        }
        if (!updated) {
            g_stream_source_seed_queue.push_back(seed);
            if (g_stream_source_seed_queue.size() > kStreamSourceSeedCap) {
                g_stream_source_seed_queue.pop_front();
            }
        }
    }

    if (g_probe_mode) {
        static LONG s_seed_log = 0;
        LONG n = InterlockedIncrement(&s_seed_log);
        if (g_ultra_log || n <= 12000) {
            std::ostringstream oss;
            oss << "SRC_SEED_PUSH handle=" << handle
                << " raw_id=" << raw_id
                << " ord=" << ord
                << " slot=" << slot
                << " flags=0x" << std::hex << flags << std::dec
                << " token=0x" << std::hex << token << std::dec
                << " uid=0x" << std::hex << uid << std::dec
                << " reason=" << (reason ? reason : "unknown")
                << " route={" << DescribeEpisodeStaticRouteEvidenceForLog(token, handle, now) << "}";
            LogLine(oss.str().c_str());
        }
    }
}

static void RememberStreamSourceSessionDirect(DWORD source_ptr,
                                              DWORD inst_ptr,
                                              DWORD buf_ptr,
                                              int handle,
                                              int raw_id,
                                              int slot,
                                              DWORD flags,
                                              unsigned short ord,
                                              unsigned long long token,
                                              unsigned long long uid,
                                              DWORD now,
                                              const char *reason) {
    if (source_ptr < 0x10000 || token == 0ULL || handle <= 0) {
        return;
    }
    EpisodeStaticRouteEvidence route_ev;
    bool token_exact = false;
    bool route_promoted = false;
    const int resolved_handle =
        ResolveStreamSourceHandleByTokenRoute(handle,
                                              token,
                                              now,
                                              &route_ev,
                                              &token_exact,
                                              &route_promoted);
    if (!token_exact) {
        if (g_probe_mode) {
            static LONG s_direct_skip = 0;
            LONG n = InterlockedIncrement(&s_direct_skip);
            if (g_ultra_log || n <= 4000) {
                std::ostringstream oss;
                oss << "SRC_SESSION_DIRECT_SKIP route_unqualified src=0x" << std::hex << source_ptr << std::dec
                    << " handle=" << handle
                    << " token=0x" << std::hex << token << std::dec
                    << " reason=" << (reason ? reason : "unknown")
                    << " static_route={" << DescribeEpisodeStaticRouteEvidenceForLog(token, handle, now) << "}";
                LogLine(oss.str().c_str());
            }
        }
        return;
    }
    if (!IsStreamSourceHandleEligible(resolved_handle)) {
        if (g_probe_mode) {
            static LONG s_direct_skip_non_stream = 0;
            LONG n = InterlockedIncrement(&s_direct_skip_non_stream);
            if (g_ultra_log || n <= 4000) {
                std::ostringstream oss;
                oss << "SRC_SESSION_DIRECT_SKIP non_stream_route src=0x" << std::hex << source_ptr << std::dec
                    << " handle=" << handle
                    << " resolved=" << resolved_handle
                    << " token=0x" << std::hex << token << std::dec
                    << " reason=" << (reason ? reason : "unknown")
                    << " route={" << DescribeEpisodeStaticRouteEvidenceForLog(token, handle, now) << "}";
                LogLine(oss.str().c_str());
            }
        }
        return;
    }
    if (IsControlRoutePromotionFromNonSubtitleCanonical(route_ev, resolved_handle)) {
        return;
    }

    StreamSourceSession session;
    session.tick = now;
    session.source_ptr = source_ptr;
    session.inst_ptr = inst_ptr;
    session.buf_ptr = buf_ptr;
    session.last_wrap_ord = ord;
    session.handle = resolved_handle;
    session.raw_id = raw_id;
    session.slot = slot;
    session.flags = flags;
    session.token = token;
    session.uid = uid;
    session.fired = WasStreamEpisodeTokenFired(token, now);

    {
        std::lock_guard<std::mutex> lock(g_stream_source_mu);
        PruneStreamSourceStateLocked(now);
        g_stream_source_sessions[source_ptr] = session;
        if (g_stream_source_sessions.size() > kStreamSourceSessionCap) {
            DWORD oldest_src = 0;
            DWORD oldest_tick = 0xffffffffu;
            for (const auto &kv : g_stream_source_sessions) {
                if (kv.second.tick < oldest_tick) {
                    oldest_tick = kv.second.tick;
                    oldest_src = kv.first;
                }
            }
            if (oldest_src != 0) {
                g_stream_source_sessions.erase(oldest_src);
            }
        }
    }

    if (g_probe_mode) {
        static LONG s_direct_log = 0;
        LONG n = InterlockedIncrement(&s_direct_log);
        if (g_ultra_log || n <= 12000) {
            std::ostringstream oss;
            oss << "SRC_SESSION_DIRECT src=0x" << std::hex << source_ptr
                << " inst=0x" << inst_ptr
                << " buf=0x" << buf_ptr << std::dec
                << " handle=" << session.handle
                << " handle_in=" << handle
                << " route_promoted=" << (route_promoted ? 1 : 0)
                << " raw_id=" << raw_id
                << " slot=" << slot
                << " ord=" << ord
                << " token=0x" << std::hex << token << std::dec
                << " uid=0x" << std::hex << uid << std::dec
                << " fired=" << (session.fired ? 1 : 0)
                << " reason=" << (reason ? reason : "unknown");
            LogLine(oss.str().c_str());
        }
    }
}

static bool TryResolveStreamSourceSessionFromWrap(DWORD source_ptr,
                                                  DWORD inst_ptr,
                                                  DWORD buf_ptr,
                                                  int id_hint,
                                                  unsigned short wrap_ord,
                                                  DWORD now,
                                                  StreamSourceSession *out_session,
                                                  bool *out_created = nullptr,
                                                  const char **out_reason = nullptr) {
    if (out_created) {
        *out_created = false;
    }
    if (out_reason) {
        *out_reason = "none";
    }
    if (!out_session || source_ptr < 0x10000) {
        return false;
    }

    std::lock_guard<std::mutex> lock(g_stream_source_mu);
    PruneStreamSourceStateLocked(now);

    auto sit = g_stream_source_sessions.find(source_ptr);
    if (sit != g_stream_source_sessions.end()) {
        StreamSourceSession &session = sit->second;
        const bool stream_hint_exact = (id_hint > 0 && IsStreamExpectedHintHandle(id_hint));
        const bool conflict = stream_hint_exact && session.handle > 0 && session.handle != id_hint;
        if (!conflict) {
            session.tick = now;
            if (inst_ptr >= 0x10000) {
                session.inst_ptr = inst_ptr;
            }
            if (buf_ptr >= 0x10000) {
                session.buf_ptr = buf_ptr;
            }
            session.last_wrap_ord = wrap_ord;
            *out_session = session;
            if (out_reason) {
                *out_reason = "existing";
            }
            return true;
        }
    }

    if (!g_stream_source_seed_fallback_mode) {
        if (g_probe_mode) {
            static LONG s_src_no_direct = 0;
            LONG n = InterlockedIncrement(&s_src_no_direct);
            if (n <= 400) {
                std::ostringstream oss;
                oss << "SRC_SESSION_SUPPRESS no_direct_session src=0x" << std::hex << source_ptr << std::dec
                    << " id_hint=" << id_hint
                    << " inst=0x" << std::hex << inst_ptr
                    << " buf=0x" << buf_ptr << std::dec
                    << " wrap_ord=" << wrap_ord;
                LogLine(oss.str().c_str());
            }
        }
        return false;
    }

    int best_index = -1;
    int best_score = -0x7fffffff;
    DWORD best_tick = 0;
    for (size_t i = 0; i < g_stream_source_seed_queue.size(); ++i) {
        const StreamSourceSeed &seed = g_stream_source_seed_queue[i];
        const DWORD age = now - seed.tick;
        if (age > kStreamSourceSeedBindWindowMs) {
            continue;
        }
        if (!IsStreamSourceHandleEligible(seed.handle)) {
            continue;
        }
        if (id_hint > 0 && IsStreamExpectedHintHandle(id_hint) && seed.handle != id_hint) {
            continue;
        }
        int score = 0;
        if (id_hint > 0 && seed.handle == id_hint) {
            score += 100;
        }
        if (seed.ord == 1077 || seed.ord == 190) {
            score += 10;
        }
        score += static_cast<int>((kStreamSourceSeedBindWindowMs - age) / 16);
        if (score > best_score || (score == best_score && seed.tick > best_tick)) {
            best_score = score;
            best_index = static_cast<int>(i);
            best_tick = seed.tick;
        }
    }
    if (best_index < 0) {
        return false;
    }

    const StreamSourceSeed picked = g_stream_source_seed_queue[best_index];
    g_stream_source_seed_queue.erase(g_stream_source_seed_queue.begin() + best_index);

    StreamSourceSession session;
    session.tick = now;
    session.source_ptr = source_ptr;
    session.inst_ptr = inst_ptr;
    session.buf_ptr = buf_ptr;
    session.last_wrap_ord = wrap_ord;
    session.handle = picked.handle;
    session.raw_id = picked.raw_id;
    session.slot = picked.slot;
    session.flags = picked.flags;
    session.token = picked.token;
    session.uid = picked.uid;
    session.fired = false;
    g_stream_source_sessions[source_ptr] = session;
    *out_session = session;
    if (out_created) {
        *out_created = true;
    }
    if (out_reason) {
        *out_reason = "seed_pick";
    }
    return true;
}

static bool TryTriggerSubtitleByStreamSourceSession(DWORD source_ptr,
                                                    DWORD inst_ptr,
                                                    DWORD buf_ptr,
                                                    int id_hint,
                                                    unsigned short wrap_ord,
                                                    DWORD unlock_off,
                                                    DWORD unlock_bytes,
                                                    DWORD now) {
    if (wrap_ord != kPseudoOrdMmfs2DsUnlockWrap ||
        source_ptr < 0x10000 ||
        buf_ptr < 0x10000 ||
        unlock_bytes == 0) {
        return false;
    }

    StreamSourceSession session;
    bool created = false;
    const char *bind_reason = nullptr;
    if (!TryResolveStreamSourceSessionFromWrap(source_ptr,
                                               inst_ptr,
                                               buf_ptr,
                                               id_hint,
                                               wrap_ord,
                                               now,
                                               &session,
                                               &created,
                                               &bind_reason)) {
        return false;
    }
    if (session.handle <= 0 || !IsStreamSourceHandleEligible(session.handle) || session.token == 0ULL) {
        return false;
    }

    EpisodeStaticRouteEvidence route_ev;
    bool token_exact = false;
    const bool route_ok =
        ResolveEpisodeStaticRouteEvidence(session.token, session.handle, now, &route_ev, &token_exact);
    if (!route_ok || !token_exact) {
        if (g_probe_mode) {
            static LONG s_route_suppress = 0;
            LONG n = InterlockedIncrement(&s_route_suppress);
            if (g_ultra_log || n <= 6000) {
                std::ostringstream oss;
                oss << "SRC_SESSION_SUPPRESS route_unqualified src=0x" << std::hex << source_ptr << std::dec
                    << " handle=" << session.handle
                    << " token=0x" << std::hex << session.token << std::dec
                    << " created=" << (created ? 1 : 0)
                    << " bind_reason=" << (bind_reason ? bind_reason : "none");
                LogLine(oss.str().c_str());
            }
        }
        return false;
    }

    if (IsControlRoutePromotionFromNonSubtitleCanonical(route_ev, session.handle)) {
        if (g_probe_mode) {
            static LONG s_control_route_non_dialog = 0;
            LONG n = InterlockedIncrement(&s_control_route_non_dialog);
            if (g_ultra_log || n <= 12000) {
                std::ostringstream oss;
                oss << "SRC_SESSION_SUPPRESS control_route_non_dialog_canon src=0x" << std::hex << source_ptr << std::dec
                    << " handle=" << session.handle
                    << " raw_id=" << session.raw_id
                    << " token=0x" << std::hex << session.token << std::dec
                    << " route_canon={" << DescribeStaticHandleForLog(route_ev.canonical_id) << "}"
                    << " route_control={" << DescribeStaticHandleForLog(route_ev.control_id) << "}";
                LogLine(oss.str().c_str());
            }
        }
        return false;
    }

    if (created && bind_reason && strcmp(bind_reason, "seed_pick") == 0) {
        if (g_probe_mode) {
            static LONG s_seed_unconfirmed = 0;
            LONG n = InterlockedIncrement(&s_seed_unconfirmed);
            if (g_ultra_log || n <= 8000) {
                std::ostringstream oss;
                oss << "SRC_SESSION_SUPPRESS seed_pick_unconfirmed src=0x" << std::hex << source_ptr << std::dec
                    << " handle=" << session.handle
                    << " raw_id=" << session.raw_id
                    << " token=0x" << std::hex << session.token << std::dec
                    << " id_hint=" << id_hint
                    << " unlock_bytes=" << unlock_bytes;
                LogLine(oss.str().c_str());
            }
        }
        return false;
    }

    DWORD dup_age_ms = 0;
    if (WasStreamEpisodeTokenFired(session.token, now, &dup_age_ms)) {
        {
            std::lock_guard<std::mutex> lock(g_stream_source_mu);
            auto it = g_stream_source_sessions.find(source_ptr);
            if (it != g_stream_source_sessions.end()) {
                it->second.tick = now;
                it->second.inst_ptr = inst_ptr;
                it->second.buf_ptr = buf_ptr;
                it->second.last_wrap_ord = wrap_ord;
                it->second.fired = true;
            }
        }
        if (g_probe_mode) {
            static LONG s_dup_suppress = 0;
            LONG n = InterlockedIncrement(&s_dup_suppress);
            if (g_ultra_log || n <= 8000) {
                std::ostringstream oss;
                oss << "SRC_SESSION_SUPPRESS token_seen src=0x" << std::hex << source_ptr << std::dec
                    << " handle=" << session.handle
                    << " token=0x" << std::hex << session.token << std::dec
                    << " age_ms=" << dup_age_ms
                    << " created=" << (created ? 1 : 0)
                    << " bind_reason=" << (bind_reason ? bind_reason : "none");
                LogLine(oss.str().c_str());
            }
        }
        return false;
    }

    SubtitleEntry *entry = FindSubtitleEntryForHandle(session.handle);
    if (!entry) {
        if (g_probe_mode) {
            static LONG s_no_entry = 0;
            LONG n = InterlockedIncrement(&s_no_entry);
            if (g_ultra_log || n <= 4000) {
                std::ostringstream oss;
                oss << "SRC_SESSION_SUPPRESS no_entry src=0x" << std::hex << source_ptr << std::dec
                    << " handle=" << session.handle
                    << " token=0x" << std::hex << session.token << std::dec;
                LogLine(oss.str().c_str());
            }
        }
        return false;
    }
    if (!g_allow_sound_only && IsSoundOnly(*entry)) {
        return false;
    }
    if (g_dialogue_only && !IsDialogueEntry(*entry)) {
        return false;
    }

    bool handled = false;
    void *buf = reinterpret_cast<void *>(static_cast<uintptr_t>(buf_ptr));
    void *prev_tls_buf = t_current_dsound_buf;
    t_current_dsound_buf = buf;
    handled = TryStartMobileByHandle(session.handle, "STREAM_SRC_SESSION");
    if (!handled) {
        const double dur = entry->duration > 0 ? entry->duration : kDefaultVoiceSec;
        QueueSubtitleEntry(*entry, dur, "STREAM_SRC_SESSION");
        handled = true;
    }
    t_current_dsound_buf = prev_tls_buf;
    if (!handled) {
        return false;
    }

    g_last_handle.store(session.handle);
    g_last_handle_tick.store(now);
    MarkStreamEpisodeTokenFired(session.token, now);
    {
        std::lock_guard<std::mutex> lock(g_stream_source_mu);
        auto it = g_stream_source_sessions.find(source_ptr);
        if (it != g_stream_source_sessions.end()) {
            it->second.tick = now;
            it->second.inst_ptr = inst_ptr;
            it->second.buf_ptr = buf_ptr;
            it->second.last_wrap_ord = wrap_ord;
            it->second.fired = true;
        }
    }

    std::ostringstream oss;
    oss << "SRC_SESSION_TRIGGER handle=" << session.handle
        << " raw_id=" << session.raw_id
        << " token=0x" << std::hex << session.token << std::dec
        << " uid=0x" << std::hex << session.uid << std::dec
        << " src=0x" << std::hex << source_ptr
        << " inst=0x" << inst_ptr
        << " buf=0x" << buf_ptr << std::dec
        << " unlock_off=0x" << std::hex << unlock_off << std::dec
        << " unlock_bytes=" << unlock_bytes
        << " id_hint=" << id_hint
        << " created=" << (created ? 1 : 0)
        << " bind_reason=" << (bind_reason ? bind_reason : "none")
        << " route={" << DescribeEpisodeStaticRouteEvidenceForLog(session.token, session.handle, now) << "}";
    LogLine(oss.str().c_str());
    return true;
}

static bool TryTriggerSubtitleByFinalSelectedId(int handle,
                                                int raw_id,
                                                unsigned long long token,
                                                unsigned long long uid,
                                                DWORD sound_ptr,
                                                DWORD buf_ptr,
                                                unsigned short ord,
                                                DWORD now) {
    if (!g_stream_final_id_mode) {
        return false;
    }
    if (handle <= 0) {
        return false;
    }
    if (token == 0ULL) {
        if (g_probe_mode) {
            static LONG s_final_id_token_zero = 0;
            LONG n = InterlockedIncrement(&s_final_id_token_zero);
            if (g_ultra_log || n <= 2000) {
                std::ostringstream oss;
                oss << "FINAL_ID_SUPPRESS token_zero handle=" << handle
                    << " raw_id=" << raw_id
                    << " uid=0x" << std::hex << uid << std::dec
                    << " ord=" << ord;
                LogLine(oss.str().c_str());
            }
        }
        return false;
    }
    if (buf_ptr < 0x10000) {
        if (g_probe_mode) {
            static LONG s_final_id_buf_unbound = 0;
            LONG n = InterlockedIncrement(&s_final_id_buf_unbound);
            if (g_ultra_log || n <= 2000) {
                std::ostringstream oss;
                oss << "FINAL_ID_SUPPRESS buf_unbound handle=" << handle
                    << " raw_id=" << raw_id
                    << " token=0x" << std::hex << token << std::dec
                    << " sound=0x" << std::hex << sound_ptr << std::dec
                    << " ord=" << ord;
                LogLine(oss.str().c_str());
            }
        }
        return false;
    }

    EpisodeStaticRouteEvidence route_ev;
    bool token_exact = false;
    bool route_promoted = false;
    const int resolved_handle =
        ResolveStreamSourceHandleByTokenRoute(handle,
                                              token,
                                              now,
                                              &route_ev,
                                              &token_exact,
                                              &route_promoted);
    // Keep final-id authority scoped to stream-expected dialogue lanes.
    if (!IsStreamSourceHandleEligible(resolved_handle)) {
        if (g_probe_mode) {
            static LONG s_final_id_non_stream = 0;
            LONG n = InterlockedIncrement(&s_final_id_non_stream);
            if (g_ultra_log || n <= 2000) {
                std::ostringstream oss;
                oss << "FINAL_ID_SUPPRESS non_stream_handle handle_in=" << handle
                    << " handle=" << resolved_handle
                    << " raw_id=" << raw_id
                    << " token=0x" << std::hex << token << std::dec
                    << " uid=0x" << std::hex << uid << std::dec
                    << " route_promoted=" << (route_promoted ? 1 : 0)
                    << " route={" << DescribeEpisodeStaticRouteEvidenceForLog(token, handle, now) << "}";
                LogLine(oss.str().c_str());
            }
        }
        return false;
    }
    if (!token_exact) {
        if (g_probe_mode) {
            static LONG s_final_id_route_suppress = 0;
            LONG n = InterlockedIncrement(&s_final_id_route_suppress);
            if (g_ultra_log || n <= 2000) {
                std::ostringstream oss;
                oss << "FINAL_ID_SUPPRESS route_unqualified"
                    << " handle=" << resolved_handle
                    << " handle_in=" << handle
                    << " raw_id=" << raw_id
                    << " token=0x" << std::hex << token << std::dec
                    << " uid=0x" << std::hex << uid << std::dec
                    << " route_promoted=" << (route_promoted ? 1 : 0)
                    << " route={" << DescribeEpisodeStaticRouteEvidenceForLog(token, handle, now) << "}";
                LogLine(oss.str().c_str());
            }
        }
        return false;
    }
    if (IsControlRoutePromotionFromNonSubtitleCanonical(route_ev, resolved_handle)) {
        return false;
    }

    DWORD dup_age_ms = 0;
    if (WasStreamEpisodeTokenFired(token, now, &dup_age_ms)) {
        if (g_probe_mode) {
            static LONG s_final_id_dup = 0;
            LONG n = InterlockedIncrement(&s_final_id_dup);
            if (g_ultra_log || n <= 4000) {
                std::ostringstream oss;
                oss << "FINAL_ID_SUPPRESS token_seen"
                    << " handle=" << resolved_handle
                    << " handle_in=" << handle
                    << " token=0x" << std::hex << token << std::dec
                    << " age_ms=" << dup_age_ms;
                LogLine(oss.str().c_str());
            }
        }
        return false;
    }

    SubtitleEntry *entry = FindSubtitleEntryForHandle(resolved_handle);
    if (!entry) {
        if (g_probe_mode) {
            static LONG s_final_id_no_entry = 0;
            LONG n = InterlockedIncrement(&s_final_id_no_entry);
            if (g_ultra_log || n <= 1200) {
                std::ostringstream oss;
                oss << "FINAL_ID_SUPPRESS no_entry handle=" << resolved_handle
                    << " handle_in=" << handle
                    << " raw_id=" << raw_id
                    << " token=0x" << std::hex << token << std::dec;
                LogLine(oss.str().c_str());
            }
        }
        return false;
    }
    if (!g_allow_sound_only && IsSoundOnly(*entry)) {
        return false;
    }
    if (g_dialogue_only && !IsDialogueEntry(*entry)) {
        return false;
    }

    void *buf = reinterpret_cast<void *>(static_cast<uintptr_t>(buf_ptr));
    void *prev_tls_buf = t_current_dsound_buf;
    t_current_dsound_buf = buf;
    bool handled = TryStartMobileByHandle(resolved_handle, "FINAL_ID");
    if (!handled) {
        const double dur = entry->duration > 0 ? entry->duration : kDefaultVoiceSec;
        QueueSubtitleEntry(*entry, dur, "FINAL_ID");
        handled = true;
    }
    t_current_dsound_buf = prev_tls_buf;
    if (!handled) {
        return false;
    }

    g_last_handle.store(resolved_handle);
    g_last_handle_tick.store(now);
    MarkStreamEpisodeTokenFired(token, now);

    std::ostringstream oss;
    oss << "FINAL_ID_TRIGGER handle=" << resolved_handle
        << " handle_in=" << handle
        << " route_promoted=" << (route_promoted ? 1 : 0)
        << " raw_id=" << raw_id
        << " token=0x" << std::hex << token << std::dec
        << " uid=0x" << std::hex << uid << std::dec
        << " ord=" << ord
        << " sound=0x" << std::hex << sound_ptr
        << " buf=0x" << buf_ptr << std::dec
        << " route={" << DescribeEpisodeStaticRouteEvidenceForLog(token, resolved_handle, now) << "}";
    LogLine(oss.str().c_str());
    return true;
}

static DWORD DecodeMmfs2WrapLengthArg(DWORD raw) {
    if (raw == 0) {
        return 0;
    }
    // Most wrapper logs show immediate length in this arg (e.g., 0x113a = 4410).
    if (raw < 0x01000000) {
        return raw;
    }
    // Some builds may pass an out-length pointer.
    if (raw >= 0x10000) {
        DWORD deref = 0;
        __try {
            deref = *reinterpret_cast<DWORD *>(raw);
        } __except (EXCEPTION_EXECUTE_HANDLER) {
            deref = 0;
        }
        if (deref > 0 && deref < 0x01000000) {
            return deref;
        }
    }
    return 0;
}

static int TryMapHandleToControlDomainRaw(int handle, unsigned short src_ord) {
    if (src_ord != 1077 && src_ord != 190) {
        return -1;
    }
    if (handle <= 61) {
        return -1;
    }
    const int raw = handle - 61;
    if (raw <= 0 || raw > 41) {
        return -1;
    }
    if (TryResolveControlDomainHandle(raw, src_ord) != handle) {
        return -1;
    }
    return raw;
}

static bool HasRecentOrd1077BindEvidence(int raw_id, int handle, DWORD now, DWORD max_age_ms) {
    if (raw_id <= 0 || handle <= 0 || max_age_ms == 0) {
        return false;
    }
    const int recent_raw = g_ord1077_recent_bind_raw_id.load(std::memory_order_relaxed);
    const int recent_handle = g_ord1077_recent_bind_handle.load(std::memory_order_relaxed);
    const DWORD recent_tick = g_ord1077_recent_bind_tick.load(std::memory_order_relaxed);
    if (recent_tick == 0) {
        return false;
    }
    if (recent_raw != raw_id || recent_handle != handle) {
        return false;
    }
    return (now - recent_tick) <= max_age_ms;
}

static bool ConsiderHandleCandidate(int candidate, bool prefer_dialog, bool *found, int *best, bool *best_dialog) {
    if (!IsHandleKnown(candidate)) {
        return false;
    }
    bool is_dialog = IsDialogHandle(candidate);
    if (!*found) {
        *best = candidate;
        *best_dialog = is_dialog;
        *found = true;
        return true;
    }
    if (prefer_dialog) {
        if (!*best_dialog && is_dialog) {
            *best = candidate;
            *best_dialog = true;
            return true;
        }
    }
    if (!*best_dialog && !is_dialog && candidate > *best) {
        *best = candidate;
        return true;
    }
    return false;
}

static bool ConsiderEncodedCandidates(int candidate, bool prefer_dialog, bool *found, int *best, bool *best_dialog) {
    bool updated = false;
    if (candidate > 0) {
        updated |= ConsiderHandleCandidate(candidate, prefer_dialog, found, best, best_dialog);
    }
    int low = candidate & 0xFFFF;
    if (low > 0 && low != candidate) {
        updated |= ConsiderHandleCandidate(low, prefer_dialog, found, best, best_dialog);
    }
    int shifted = candidate >> 1;
    if (shifted > 0 && shifted != candidate) {
        updated |= ConsiderHandleCandidate(shifted, prefer_dialog, found, best, best_dialog);
    }
    int low_shifted = low >> 1;
    if (low_shifted > 0 && low_shifted != low) {
        updated |= ConsiderHandleCandidate(low_shifted, prefer_dialog, found, best, best_dialog);
    }
    return updated;
}

static bool TryHandleFromPtr(DWORD ptr, int *out_handle, bool prefer_dialog) {
    if (ptr < 0x10000) {
        return false;
    }
    int best = 0;
    bool found = false;
    bool best_dialog = false;
    for (DWORD off = 0; off <= 0x200; off += 2) {
        DWORD val = 0;
        WORD wval = 0;
        __try {
            if ((off & 3) == 0) {
                val = *reinterpret_cast<DWORD *>(ptr + off);
            }
            wval = *reinterpret_cast<WORD *>(ptr + off);
        } __except (EXCEPTION_EXECUTE_HANDLER) {
            continue;
        }
        if ((off & 3) == 0 && val != 0) {
            ConsiderEncodedCandidates(static_cast<int>(val), prefer_dialog, &found, &best, &best_dialog);
            if (!prefer_dialog && found) {
                break;
            }
        }
        if (wval != 0) {
            ConsiderEncodedCandidates(static_cast<int>(wval), prefer_dialog, &found, &best, &best_dialog);
            if (!prefer_dialog && found) {
                break;
            }
        }
    }
    if (found) {
        if (out_handle) {
            *out_handle = best;
        }
        return true;
    }
    return false;
}

static bool ReadAsciiStringAt(DWORD ptr, std::string &out) {
    out.clear();
    if (ptr < 0x10000) {
        return false;
    }
    const int kMaxLen = 128;
    for (int i = 0; i < kMaxLen; i++) {
        char c = 0;
        __try {
            c = *reinterpret_cast<char *>(ptr + i);
        } __except (EXCEPTION_EXECUTE_HANDLER) {
            return false;
        }
        if (c == '\0') {
            break;
        }
        unsigned char uc = static_cast<unsigned char>(c);
        if (uc < 0x20 || uc > 0x7E) {
            return false;
        }
        out.push_back(c);
    }
    return !out.empty();
}

static bool ReadWideStringAt(DWORD ptr, std::string &out) {
    out.clear();
    if (ptr < 0x10000) {
        return false;
    }
    const int kMaxLen = 128;
    for (int i = 0; i < kMaxLen; i++) {
        wchar_t c = 0;
        __try {
            c = *reinterpret_cast<wchar_t *>(ptr + i * 2);
        } __except (EXCEPTION_EXECUTE_HANDLER) {
            return false;
        }
        if (c == L'\0') {
            break;
        }
        if (c < 0x20 || c > 0x7E) {
            return false;
        }
        out.push_back(static_cast<char>(c));
    }
    return !out.empty();
}

// Forward decls: these helpers are defined later but used by deep name resolution.
static bool TryReadPtr(DWORD base, DWORD *out_ptr);
static bool TryReadU32(DWORD base, int offset, DWORD *out_val);
static bool TryHandleFromStringPtr(DWORD ptr, int *out_handle) {
    std::string s;
    // Prefer UTF-16 first. MMFS2 by-name calls often pass wide strings,
    // and ASCII-first would misread "H\0a\0..." as just "H".
    if (!ReadWideStringAt(ptr, s)) {
        if (!ReadAsciiStringAt(ptr, s)) {
            return false;
        }
    }
    std::string norm = NormalizeName(s);
    if (norm.empty()) {
        return false;
    }
    auto it = g_sound_name_rev.find(norm);
    if (it == g_sound_name_rev.end()) {
        return false;
    }
    int h = it->second;
    if (!IsDialogHandleValue(h) && !IsStreamExpectedHintHandle(h)) {
        return false;
    }
    if (out_handle) {
        *out_handle = h;
    }
    return true;
}

static bool TryHandleFromStringPtrDeep(DWORD ptr, int *out_handle, int *out_depth = nullptr, int *out_off = nullptr) {
    if (out_depth) {
        *out_depth = -1;
    }
    if (out_off) {
        *out_off = -1;
    }
    if (ptr < 0x10000) {
        return false;
    }

    std::unordered_set<DWORD> seen;
    seen.reserve(32);

    auto try_one = [&](DWORD cand, int depth, int off) -> bool {
        if (cand < 0x10000) {
            return false;
        }
        if (seen.find(cand) != seen.end()) {
            return false;
        }
        seen.insert(cand);
        int h = 0;
        if (!TryHandleFromStringPtr(cand, &h)) {
            return false;
        }
        if (out_handle) {
            *out_handle = h;
        }
        if (out_depth) {
            *out_depth = depth;
        }
        if (out_off) {
            *out_off = off;
        }
        return true;
    };

    if (try_one(ptr, 0, 0)) {
        return true;
    }

    static const int kNamePtrOffsets[] = {0, 4, 8, 0x0c, 0x10, 0x14, 0x18, 0x1c, 0x20};
    for (size_t i = 0; i < sizeof(kNamePtrOffsets) / sizeof(kNamePtrOffsets[0]); i++) {
        const int off = kNamePtrOffsets[i];
        DWORD p1 = 0;
        if (off == 0) {
            p1 = ptr;
        } else if (!TryReadU32(ptr, off, &p1)) {
            continue;
        }
        if (try_one(p1, 1, off)) {
            return true;
        }

        DWORD p2 = 0;
        if (TryReadPtr(p1, &p2) && try_one(p2, 2, off)) {
            return true;
        }

        DWORD p3 = 0;
        if (TryReadU32(p1, 4, &p3) && try_one(p3, 2, off)) {
            return true;
        }
    }
    return false;
}
static bool ResolveHandleFromArgs(const DWORD *args, int arg_count, int *handle, int *arg_index, bool prefer_dialog) {
    if (!args || arg_count <= 0) {
        return false;
    }
    if (g_use_dsound_trigger && g_strict_arg_handle) {
        for (int i = 0; i < arg_count; i++) {
            int candidate = static_cast<int>(args[i]);
            if (IsDialogHandleValue(candidate)) {
                if (handle) *handle = candidate;
                if (arg_index) *arg_index = i + 1;
                return true;
            }
        }
        return false;
    }
    int best = 0;
    bool found = false;
    bool best_dialog = false;
    int best_arg = 1;
    if (prefer_dialog) {
        for (int i = 0; i < arg_count; i++) {
            int candidate = static_cast<int>(args[i]);
            if (ConsiderEncodedCandidates(candidate, true, &found, &best, &best_dialog)) {
                best_arg = i + 1;
            }
        }
        if (found && best_dialog) {
            if (handle) *handle = best;
            if (arg_index) *arg_index = best_arg;
            return true;
        }
    }
    for (int i = 0; i < arg_count; i++) {
        int candidate = static_cast<int>(args[i]);
        if (ConsiderEncodedCandidates(candidate, false, &found, &best, &best_dialog)) {
            best_arg = i + 1;
        }
    }
    if (found) {
        if (handle) *handle = best;
        if (arg_index) *arg_index = best_arg;
        return true;
    }
    for (int i = 0; i < arg_count; i++) {
        int found_handle = 0;
        if (TryHandleFromPtr(static_cast<DWORD>(args[i]), &found_handle, prefer_dialog)) {
            if (handle) *handle = found_handle;
            if (arg_index) *arg_index = i + 1;
            return true;
        }
    }
    if (handle) *handle = static_cast<int>(args[0]);
    if (arg_index) *arg_index = 1;
    return false;
}

static bool TryResolveHandleFromPtrArgs(const DWORD *args, int arg_count, int *handle, int *arg_index, bool prefer_dialog) {
    if (!args || arg_count <= 0) {
        return false;
    }
    for (int i = 0; i < arg_count; i++) {
        int found_handle = 0;
        if (TryHandleFromPtr(static_cast<DWORD>(args[i]), &found_handle, prefer_dialog)) {
            if (IsDialogHandleValue(found_handle)) {
                if (handle) *handle = found_handle;
                if (arg_index) *arg_index = i + 1;
                return true;
            }
        }
    }
    return false;
}

static bool TryReadHandleAt(DWORD base, int offset, int *out_handle);
static bool FindDialogHandleInPtr(DWORD ptr, int *handle, int *offset) {
    if (!ptr || ptr < 0x10000) {
        return false;
    }
    int found = 0;
    for (int off = 0; off <= 0x100; off += 2) {
        int candidate = 0;
        if (!TryReadHandleAt(ptr, off, &candidate)) {
            continue;
        }
        if (IsDialogHandle(candidate)) {
            found = candidate;
            if (handle) *handle = candidate;
            if (offset) *offset = off;
            return true;
        }
    }
    return false;
}

static void CollectDialogHandlesInPtr(DWORD ptr, int *out, int *count, int max_count) {
    if (!out || !count || max_count <= 0) {
        return;
    }
    if (!ptr || ptr < 0x10000) {
        return;
    }
    for (int off = 0; off <= 0x100 && *count < max_count; off += 2) {
        int candidate = 0;
        if (!TryReadHandleAt(ptr, off, &candidate)) {
            continue;
        }
        if (!IsDialogHandleValue(candidate)) {
            continue;
        }
        bool dup = false;
        for (int i = 0; i < *count; i++) {
            if (out[i] == candidate) {
                dup = true;
                break;
            }
        }
        if (dup) {
            continue;
        }
        out[(*count)++] = candidate;
    }
}

