static bool IsVampSoapHandle(int handle) {
    auto it = g_sound_name_map.find(handle);
    if (it == g_sound_name_map.end()) {
        return false;
    }
    // Keep this check strict; we only want to auto-schedule for the long TV show clips.
    return it->second.rfind("VampSoap_", 0) == 0;
}

static bool ShouldPreferMobileSchedule(int handle, const SubtitleEntry *entry) {
    // Apply mobile schedules globally when they exist. This provides the closest behavior to the mobile version:
    // timed, line-by-line subtitles instead of dumping all sentences at once.
    //
    // We still respect existing filters for known entries (dialogue-only / sound-only).
    if (!HasMobileDialogHandle(handle)) {
        return false;
    }
    if (entry) {
        if (!g_allow_sound_only && IsSoundOnly(*entry)) {
            return false;
        }
        if (g_dialogue_only && !IsDialogueEntry(*entry)) {
            return false;
        }
    }
    return true;
}
static std::wstring g_current_text;
struct ActiveSubtitleLine {
    std::wstring slot; // empty = stack-mode (no replacement); non-empty = replace same-slot line
    std::wstring text;
    COLORREF color;
    DWORD end_ms;
};
static std::deque<ActiveSubtitleLine> g_active_lines;
static const int kMaxActiveLines = 4;
static const int kActiveLineGapPx = 8;

static void PurgeExpiredLinesLocked(DWORD now) {
    for (auto it = g_active_lines.begin(); it != g_active_lines.end();) {
        if (now > it->end_ms) {
            it = g_active_lines.erase(it);
        } else {
            ++it;
        }
    }
}

static void EraseLinesBySlotLocked(const std::wstring &slot) {
    if (slot.empty()) {
        return;
    }
    for (auto it = g_active_lines.begin(); it != g_active_lines.end();) {
        if (it->slot == slot) {
            it = g_active_lines.erase(it);
        } else {
            ++it;
        }
    }
}

static void UpsertActiveLineLocked(const std::wstring &slot, const std::wstring &text, COLORREF color, DWORD end_ms, DWORD now) {
    if (!slot.empty()) {
        EraseLinesBySlotLocked(slot);
    }
    PurgeExpiredLinesLocked(now);
    while (g_active_lines.size() >= static_cast<size_t>(kMaxActiveLines)) {
        g_active_lines.pop_front();
    }
    ActiveSubtitleLine line;
    line.slot = slot;
    line.text = text;
    line.color = color;
    line.end_ms = end_ms;
    g_active_lines.push_back(line);
}

static std::wstring WidenAscii(const std::string &s) {
    return std::wstring(s.begin(), s.end());
}

static std::wstring SpeakerSlotFromTag(const std::wstring &speaker) {
    // Per-speaker slots allow multiple overlapping subtitles without clobbering each other,
    // while still replacing repeated lines from the same speaker.
    if (speaker.empty()) {
        return L"";
    }
    std::wstring sp = speaker;
    // trim
    size_t a = 0;
    while (a < sp.size() && iswspace(sp[a])) a++;
    size_t b = sp.size();
    while (b > a && iswspace(sp[b - 1])) b--;
    sp = (b > a) ? sp.substr(a, b - a) : L"";
    if (sp.empty()) {
        return L"";
    }
    // Strip surrounding [ ] for tags like "[HandUnit]" to keep slots stable.
    if (sp.size() >= 2 && sp.front() == L'[' && sp.back() == L']') {
        sp = sp.substr(1, sp.size() - 2);
    }
    // Compact whitespace.
    std::wstring compact;
    compact.reserve(sp.size());
    for (wchar_t c : sp) {
        if (!iswspace(c)) {
            compact.push_back(c);
        }
    }
    if (compact.empty()) {
        return L"";
    }
    return L"spk:" + compact;
}

static std::wstring MobileSlotFromName(const std::string &norm_name) {
    return L"mob:" + WidenAscii(norm_name);
}

static std::wstring ExtractBracketSpeakerTag(const std::wstring &text) {
    size_t i = 0;
    while (i < text.size() && iswspace(text[i])) {
        i++;
    }
    if (i >= text.size() || text[i] != L'[') {
        return L"";
    }
    size_t close = text.find(L']', i + 1);
    if (close == std::wstring::npos || close <= i + 1) {
        return L"";
    }
    std::wstring tag = text.substr(i + 1, close - (i + 1));
    // trim
    size_t a = 0;
    while (a < tag.size() && iswspace(tag[a])) a++;
    size_t b = tag.size();
    while (b > a && iswspace(tag[b - 1])) b--;
    if (b <= a) {
        return L"";
    }
    return tag.substr(a, b - a);
}
