static void LoadMmfs2HandleMap() {
    if (!g_use_handle_map) {
        LogLine("mmfs2 handle map disabled");
        return;
    }
    wchar_t path[MAX_PATH] = {0};
    if (!GetModuleFileNameW(NULL, path, MAX_PATH)) {
        return;
    }
    wchar_t *slash = wcsrchr(path, L'\\');
    if (!slash) {
        return;
    }
    *slash = L'\0';
    std::wstring file = std::wstring(path) + L"\\mmfs2_handle_map.txt";
    std::ifstream in(file.c_str(), std::ios::in | std::ios::binary);
    if (!in.is_open()) {
        return;
    }
    int count = 0;
    std::string line;
    while (std::getline(in, line)) {
        if (line.empty()) {
            continue;
        }
        int ord = 0;
        int arg = 0;
        int offset = 0;
        if (!ParseOrdinalArgOffsetLine(line, &ord, &arg, &offset)) {
            continue;
        }
        if (ord <= 0 || ord >= 65536) {
            continue;
        }
        if (arg < 0 || arg > kMaxMmfs2Args) {
            continue;
        }
        if (offset < 0 || offset > 0x400) {
            continue;
        }
        g_mmfs2_handle_map[MakeHandleArgKey(static_cast<unsigned short>(ord), arg)] = offset;
        count++;
    }
    if (count > 0) {
        std::ostringstream oss;
        oss << "mmfs2 handle map loaded: " << count;
        LogLine(oss.str().c_str());
    }
}

